import { Component, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface ApiResponse {
  status: number;
  statusText: string;
  elapsed: number;
  body: string;
  headers: Record<string, string>;
}

interface HistoryItem {
  method: string;
  url: string;
  body: string;
  headersText: string;
  at: number;
}

const METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'HEAD'] as const;
type HttpMethod = (typeof METHODS)[number];

function parseHeaderLines(raw: string): Record<string, string> {
  const o: Record<string, string> = {};
  for (const line of raw.split('\n')) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const i = t.indexOf(':');
    if (i > 0) {
      const k = t.slice(0, i).trim();
      const v = t.slice(i + 1).trim();
      if (k) o[k] = v;
    }
  }
  return o;
}

@Component({
  selector: 'app-api-tester-widget',
  imports: [FormsModule],
  templateUrl: './api-tester-widget.component.html',
  styleUrl: './api-tester-widget.component.scss',
})
export class ApiTesterWidgetComponent {
  readonly methods = METHODS;
  readonly method = signal<HttpMethod>('GET');
  readonly url = signal('');
  readonly body = signal('');
  readonly requestHeadersText = signal('');
  readonly bearerToken = signal('');
  readonly basicUser = signal('');
  readonly basicPassword = signal('');
  readonly loading = signal(false);
  readonly response = signal<ApiResponse | null>(null);
  readonly error = signal('');
  readonly showBody = signal(false);
  readonly showReqHeaders = signal(false);
  readonly showRespHeaders = signal(true);
  readonly history = signal<HistoryItem[]>([]);

  get statusColor(): string {
    const s = this.response()?.status ?? 0;
    if (s >= 200 && s < 300) return 'success';
    if (s >= 300 && s < 400) return 'warn';
    return 'error';
  }

  formattedBody(): string {
    const raw = this.response()?.body ?? '';
    try {
      return JSON.stringify(JSON.parse(raw), null, 2);
    } catch {
      return raw;
    }
  }

  responseHeaderLines(): { key: string; value: string }[] {
    const h = this.response()?.headers ?? {};
    return Object.keys(h)
      .sort()
      .map((key) => ({ key, value: h[key] }));
  }

  responseHeadersFormatted(): string {
    return this.responseHeaderLines()
      .map((l) => `${l.key}: ${l.value}`)
      .join('\n');
  }

  historyUrlShort(u: string): string {
    return u.length > 36 ? u.slice(0, 36) + '…' : u;
  }

  applyBearer(): void {
    const t = this.bearerToken().trim();
    if (!t) return;
    const cur = this.requestHeadersText();
    const lines = cur.split('\n').filter((l) => !/^authorization\s*:/i.test(l.trim()));
    const next = [...lines, `Authorization: Bearer ${t}`].join('\n');
    this.requestHeadersText.set(next);
  }

  applyBasic(): void {
    const u = this.basicUser().trim();
    if (!u) return;
    const p = this.basicPassword();
    const token = typeof btoa === 'function' ? btoa(`${u}:${p}`) : '';
    if (!token) return;
    const cur = this.requestHeadersText();
    const lines = cur.split('\n').filter((l) => !/^authorization\s*:/i.test(l.trim()));
    const next = [...lines, `Authorization: Basic ${token}`].join('\n');
    this.requestHeadersText.set(next);
  }

  loadHistoryItem(h: HistoryItem): void {
    this.method.set(h.method as HttpMethod);
    this.url.set(h.url);
    this.body.set(h.body);
    this.requestHeadersText.set(h.headersText);
  }

  async send(): Promise<void> {
    const target = this.url().trim();
    if (!target) return;
    this.loading.set(true);
    this.response.set(null);
    this.error.set('');
    const start = Date.now();
    const m = this.method();
    const headerObj = parseHeaderLines(this.requestHeadersText());
    if (m !== 'GET' && m !== 'HEAD' && this.body().trim()) {
      if (!headerObj['Content-Type'] && !headerObj['content-type']) {
        headerObj['Content-Type'] = 'application/json';
      }
    }
    try {
      const init: RequestInit = {
        method: m,
        headers: headerObj,
      };
      if (m !== 'GET' && m !== 'HEAD' && this.body().trim()) {
        init.body = this.body();
      }
      const res = await fetch(target, init);
      const text = await res.text();
      const headers: Record<string, string> = {};
      res.headers.forEach((v, k) => {
        headers[k] = v;
      });
      this.response.set({
        status: res.status,
        statusText: res.statusText,
        elapsed: Date.now() - start,
        body: text,
        headers,
      });
      this.history.update((list) => {
        const item: HistoryItem = {
          method: m,
          url: target,
          body: this.body(),
          headersText: this.requestHeadersText(),
          at: Date.now(),
        };
        return [item, ...list.filter((x) => x.url !== target || x.method !== m)].slice(0, 20);
      });
    } catch (err) {
      this.error.set(err instanceof Error ? err.message : String(err));
    } finally {
      this.loading.set(false);
    }
  }
}

import { Component, computed, effect, inject, signal } from '@angular/core';
import { TitleCasePipe } from '@angular/common';
import { WorkspaceService } from '@core/services/workspace.service';
import { ToastService } from '@core/services/toast.service';
import { FormsModule } from '@angular/forms';
import {
  COMPANION_SNAPSHOT_VERSION,
  IPC_CHANNELS,
  defaultFeatureFlags,
  mergeFeatureFlags,
  type AutofillHintDTO,
  type AutomationRuleDTO,
  type CompanionSnapshotV1,
  type DevLensFeatureFlags,
  type DevLensFeatureFlagsPatch,
  type DevLensShortcutProfileFileV1,
  type DevLensStoreSnapshot,
  type DevLensThemeFileV1,
} from '@dev-lens/shared';
import { BackupCryptoService } from '@core/services/backup-crypto.service';
import { ElectronBridgeService } from '@core/services/electron-bridge.service';
import { PersistedStateService } from '@core/services/persisted-state.service';
import { PluginRuntimeService } from '@core/services/plugin-runtime.service';
import {
  SHORTCUT_DEFAULTS,
  buildMergedShortcutBindings,
  describeShortcutConflicts,
} from '@core/services/shortcut-registry.service';
import { THEME_CSS_VARIABLE_KEYS } from '@core/theme-tokens';
import {
  mergeAutomationRulesLww,
  mergeBookmarksLww,
  mergeClipboardLww,
  mergeNotesLww,
  mergePluginStatesLww,
  mergePluginStorageLww,
  mergeReadLaterLww,
  mergeSavedSessionsLww,
  mergeWorkspacesLww,
} from '@core/backup-merge';

/** Decrypted encrypted-backup payload (v1). */
interface BackupImportPayload {
  bookmarks?: DevLensStoreSnapshot['bookmarks'];
  notes?: DevLensStoreSnapshot['notes'];
  readLater?: DevLensStoreSnapshot['readLater'];
  workspaces?: DevLensStoreSnapshot['workspaces'];
  activeWorkspaceId?: DevLensStoreSnapshot['activeWorkspaceId'];
  settings?: DevLensStoreSnapshot['settings'];
  savedSessions?: DevLensStoreSnapshot['savedSessions'];
  automationRules?: DevLensStoreSnapshot['automationRules'];
  tabGroups?: DevLensStoreSnapshot['tabGroups'];
  openTabs?: DevLensStoreSnapshot['openTabs'];
  clipboardHistory?: DevLensStoreSnapshot['clipboardHistory'];
  history?: DevLensStoreSnapshot['history'];
  pluginStates?: DevLensStoreSnapshot['pluginStates'];
  pluginStorage?: DevLensStoreSnapshot['pluginStorage'];
}

export interface InstalledExtensionInfo {
  id: string;
  name: string;
  version: string;
  description: string;
  iconDataUrl: string | null;
  popupPath: string | null;
}

type Section =
  | 'general'
  | 'features'
  | 'privacy'
  | 'appearance'
  | 'automation'
  | 'shortcuts'
  | 'ai'
  | 'plugins'
  | 'extensions'
  | 'sync'
  | 'advanced';

type SettingsShape = DevLensStoreSnapshot['settings'];

@Component({
  selector: 'app-settings',
  imports: [FormsModule, TitleCasePipe],
  templateUrl: './settings.component.html',
  styleUrl: './settings.component.scss',
})
export class SettingsComponent {
  readonly persisted = inject(PersistedStateService);
  readonly bridge = inject(ElectronBridgeService);
  readonly pluginRuntime = inject(PluginRuntimeService);
  readonly backupCrypto = inject(BackupCryptoService);
  private readonly toast = inject(ToastService);
  private readonly workspaceSvc = inject(WorkspaceService);

  readonly workspaces = computed(() => this.workspaceSvc.workspaces());

  readonly section = signal<Section>('general');
  readonly blockListStatus = signal<string>('');
  readonly shortcutConflicts = signal<string[]>([]);
  readonly installedExtensions = signal<InstalledExtensionInfo[]>([]);
  readonly extLoading = signal(false);
  readonly themeRegistryEntries = signal<{ id: string; name: string; sourceUrl?: string }[]>([]);

  readonly backupExportOpen = signal(false);
  readonly backupExportPass = signal('');
  readonly backupExportPass2 = signal('');

  readonly backupImportOpen = signal(false);
  readonly backupImportJson = signal<string | null>(null);
  readonly backupImportPass = signal('');
  readonly backupImportStep = signal<'pass' | 'confirm'>('pass');
  readonly backupImportDecoded = signal<BackupImportPayload | null>(null);

  readonly resetDataConfirmOpen = signal(false);
  readonly shortcutsResetConfirmOpen = signal(false);

  readonly apiKeyVisible = signal(false);

  readonly nav: { id: Section; label: string; icon: string }[] = [
    { id: 'general', label: 'General', icon: 'fa-gear' },
    { id: 'features', label: 'Features', icon: 'fa-sliders' },
    { id: 'privacy', label: 'Privacy', icon: 'fa-shield-halved' },
    { id: 'appearance', label: 'Appearance', icon: 'fa-palette' },
    { id: 'automation', label: 'Automation', icon: 'fa-bolt' },
    { id: 'ai', label: 'AI', icon: 'fa-robot' },
    { id: 'shortcuts', label: 'Shortcuts', icon: 'fa-keyboard' },
    { id: 'plugins', label: 'Plugins', icon: 'fa-puzzle-piece' },
    { id: 'extensions', label: 'Extensions', icon: 'fa-cubes' },
    { id: 'sync', label: 'Sync & backup', icon: 'fa-cloud-arrow-up' },
    { id: 'advanced', label: 'Advanced', icon: 'fa-wrench' },
  ];

  readonly shortcutRows: { id: string; label: string }[] = [
    { id: 'spotlight', label: 'Spotlight' },
    { id: 'newTab', label: 'New tab' },
    { id: 'closeTab', label: 'Close tab' },
    { id: 'cycleTabNext', label: 'Next tab' },
    { id: 'cycleTabPrev', label: 'Previous tab' },
    { id: 'toggleSplit', label: 'Toggle split view' },
    { id: 'focusMode', label: 'Focus mode' },
    { id: 'toggleDevtools', label: 'Toggle DevTools' },
    { id: 'inspectElement', label: 'Inspect element (at pointer)' },
  ];

  constructor() {
    effect(() => {
      const snap = this.persisted.snapshot();
      if (!snap) {
        this.shortcutConflicts.set([]);
        return;
      }
      const merged = buildMergedShortcutBindings(snap.settings.shortcutBindings ?? {});
      this.shortcutConflicts.set(describeShortcutConflicts(merged));
    });
    effect(() => {
      if (this.section() === 'plugins' && this.bridge.isElectron) {
        void this.pluginRuntime.refresh();
      }
    });
    effect(() => {
      if (this.section() === 'extensions' && this.bridge.isElectron) {
        void this.loadExtensions();
      }
    });
    effect(() => {
      if (this.section() !== 'appearance') return;
      void fetch('/theme-registry.json')
        .then((r) => (r.ok ? r.json() : Promise.resolve(null)))
        .then((data: { themes?: { id: string; name: string; sourceUrl?: string }[] } | null) => {
          const arr = data?.themes && Array.isArray(data.themes) ? data.themes : [];
          this.themeRegistryEntries.set(arr);
        })
        .catch(() => this.themeRegistryEntries.set([]));
    });
  }

  async patchSettings(p: Partial<SettingsShape>): Promise<void> {
    const cur = this.persisted.snapshot()?.settings;
    if (!cur) return;
    await this.persisted.patch({ settings: { ...cur, ...p } });
  }

  /** Effective feature flags for display (defaults merged). */
  effectiveFeatureFlags(snap: DevLensStoreSnapshot): DevLensFeatureFlags {
    return mergeFeatureFlags(defaultFeatureFlags(), snap.settings.featureFlags);
  }

  async patchFeatureFlags(p: DevLensFeatureFlagsPatch): Promise<void> {
    const cur = this.persisted.snapshot()?.settings;
    if (!cur) return;
    const base = cur.featureFlags ?? defaultFeatureFlags();
    await this.patchSettings({ featureFlags: mergeFeatureFlags(base, p) });
  }

  allowlistLines(snap: DevLensStoreSnapshot): string {
    return (snap.settings.trackerAllowlistHosts ?? []).join('\n');
  }

  async setAllowlistText(text: string): Promise<void> {
    const hosts = text
      .split(/[\n,]+/)
      .map((s) => s.trim())
      .filter(Boolean);
    await this.patchSettings({ trackerAllowlistHosts: hosts });
  }

  focusAllowlistLines(snap: DevLensStoreSnapshot): string {
    return (snap.settings.focusModeAllowlistHosts ?? []).join('\n');
  }

  async setFocusAllowlistText(text: string): Promise<void> {
    const hosts = text
      .split(/[\n,]+/)
      .map((s) => s.trim())
      .filter(Boolean);
    await this.patchSettings({ focusModeAllowlistHosts: hosts });
  }

  userBlockedLines(snap: DevLensStoreSnapshot): string {
    return (snap.settings.userBlockedHosts ?? []).join('\n');
  }

  async setUserBlockedText(text: string): Promise<void> {
    const hosts = text
      .split(/[\n,]+/)
      .map((s) => s.trim())
      .filter(Boolean);
    await this.patchSettings({ userBlockedHosts: hosts });
  }

  async refreshRemoteBlockList(): Promise<void> {
    if (!this.bridge.isElectron) return;
    this.blockListStatus.set('Updating…');
    const r = await this.bridge.invoke<{ ok: boolean; count?: number; error?: string }>(
      IPC_CHANNELS.BLOCKER_REFRESH_LIST,
    );
    if (r.ok) this.blockListStatus.set(`Loaded ${r.count ?? 0} host rules.`);
    else this.blockListStatus.set(r.error ?? 'Update failed.');
  }

  async setStartup(b: 'restore' | 'new-tab'): Promise<void> {
    const cur = this.persisted.snapshot()?.settings;
    if (!cur) return;
    await this.persisted.patch({ settings: { ...cur, startupBehavior: b } });
  }

  async setLanguage(lang: string): Promise<void> {
    const cur = this.persisted.snapshot()?.settings;
    if (!cur) return;
    await this.persisted.patch({ settings: { ...cur, language: lang } });
  }

  requestResetData(): void {
    this.resetDataConfirmOpen.set(true);
  }

  cancelResetData(): void {
    this.resetDataConfirmOpen.set(false);
  }

  async confirmResetData(): Promise<void> {
    this.resetDataConfirmOpen.set(false);
    await this.persisted.patch({
      openTabs: [],
      bookmarks: [],
      history: [],
      notes: [],
      tabGroups: [],
    });
    window.location.reload();
  }

  shortcutDisplayValue(snap: DevLensStoreSnapshot, actionId: string): string {
    return snap.settings.shortcutBindings[actionId] ?? SHORTCUT_DEFAULTS[actionId] ?? '';
  }

  async updateShortcutBinding(actionId: string, raw: string): Promise<void> {
    const cur = this.persisted.snapshot()?.settings;
    if (!cur) return;
    const v = raw.trim().toLowerCase();
    const next = { ...cur.shortcutBindings };
    const def = SHORTCUT_DEFAULTS[actionId];
    if (!v || (def && v === def)) {
      delete next[actionId];
    } else {
      next[actionId] = v;
    }
    const trial = buildMergedShortcutBindings(next);
    if (describeShortcutConflicts(trial).length > 0) {
      this.toast.error(
        'That combo is already used by another action. Choose a different shortcut.',
      );
      return;
    }
    await this.patchSettings({ shortcutBindings: next });
  }

  requestResetAllShortcuts(): void {
    this.shortcutsResetConfirmOpen.set(true);
  }

  cancelShortcutsReset(): void {
    this.shortcutsResetConfirmOpen.set(false);
  }

  async confirmResetAllShortcuts(): Promise<void> {
    this.shortcutsResetConfirmOpen.set(false);
    await this.patchSettings({ shortcutBindings: {} });
    this.toast.show('Shortcuts reset to defaults.');
  }

  exportShortcutProfile(): void {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const payload: DevLensShortcutProfileFileV1 = {
      version: 1,
      bindings: { ...snap.settings.shortcutBindings },
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-shortcuts-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  onImportShortcutProfilePick(ev: Event): void {
    const input = ev.target as HTMLInputElement;
    const file = input.files?.[0];
    input.value = '';
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      void (async () => {
        try {
          const o = JSON.parse(reader.result as string) as DevLensShortcutProfileFileV1;
          if (o.version !== 1 || !o.bindings || typeof o.bindings !== 'object') {
            this.toast.error('Invalid shortcut profile file.');
            return;
          }
          const cur = this.persisted.snapshot()?.settings;
          if (!cur) return;
          const merged = buildMergedShortcutBindings(o.bindings);
          if (describeShortcutConflicts(merged).length > 0) {
            this.toast.error('This profile contains conflicting shortcuts. Import aborted.');
            return;
          }
          await this.patchSettings({ shortcutBindings: { ...o.bindings } });
          this.toast.show('Shortcut profile imported.');
        } catch {
          this.toast.error('Could not read shortcut profile JSON.');
        }
      })();
    };
    reader.readAsText(file);
  }

  exportThemeFile(): void {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const el = document.documentElement;
    const variables: Record<string, string> = {};
    for (const k of THEME_CSS_VARIABLE_KEYS) {
      variables[k] = getComputedStyle(el).getPropertyValue(k).trim();
    }
    const payload: DevLensThemeFileV1 = {
      version: 1,
      themePreset: snap.settings.themePreset,
      variables,
      customThemeVariables: snap.settings.customThemeVariables ?? {},
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-theme-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  onImportThemePick(ev: Event): void {
    const input = ev.target as HTMLInputElement;
    const file = input.files?.[0];
    input.value = '';
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      void (async () => {
        try {
          const o = JSON.parse(reader.result as string) as DevLensThemeFileV1 & {
            version?: number;
          };
          if (o.version !== undefined && o.version !== 1) {
            this.toast.error('Unsupported theme file version.');
            return;
          }
          const varsA = o.variables && typeof o.variables === 'object' ? o.variables : {};
          const varsB =
            o.customThemeVariables && typeof o.customThemeVariables === 'object'
              ? o.customThemeVariables
              : {};
          const customThemeVariables: Record<string, string> = { ...varsA, ...varsB };
          const preset = o.themePreset;
          const allowed = new Set(['dark', 'light', 'midnight', 'solarized', 'high-contrast']);
          await this.patchSettings({
            ...(preset && allowed.has(preset)
              ? { themePreset: preset as SettingsShape['themePreset'] }
              : {}),
            customThemeVariables,
          });
          this.toast.show('Theme imported.');
        } catch {
          this.toast.error('Could not read theme JSON.');
        }
      })();
    };
    reader.readAsText(file);
  }

  async addAutomationRule(): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const r: AutomationRuleDTO = {
      id: crypto.randomUUID(),
      enabled: true,
      name: 'New rule',
      triggerType: 'url_contains',
      triggerValue: '',
      actionType: 'open_widget',
      actionValue: 'ai',
    };
    await this.persisted.patch({ automationRules: [...snap.automationRules, r] });
  }

  async patchAutomationRules(rules: AutomationRuleDTO[]): Promise<void> {
    await this.persisted.patch({ automationRules: rules });
  }

  async updateRule(id: string, patch: Partial<AutomationRuleDTO>): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const next = snap.automationRules.map((r) => (r.id === id ? { ...r, ...patch } : r));
    await this.patchAutomationRules(next);
  }

  async removeRule(id: string): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    await this.patchAutomationRules(snap.automationRules.filter((r) => r.id !== id));
  }

  /** Curated marketplace rules — maintained by the Dev-Lens team. */
  readonly marketplaceRules: (Omit<AutomationRuleDTO, 'id'> & { description: string })[] = [
    {
      enabled: true,
      name: 'Work hours — open Notes',
      description: 'Opens the Notes widget automatically during working hours (09:00–17:00 local).',
      triggerType: 'time_window',
      triggerValue: '09:00-17:00',
      actionType: 'open_widget',
      actionValue: 'notes',
    },
    {
      enabled: true,
      name: 'GitHub — open AI summary',
      description:
        'When navigating to GitHub, opens the AI assistant to help summarise PRs and issues.',
      triggerType: 'url_contains',
      triggerValue: 'github.com',
      actionType: 'open_widget',
      actionValue: 'ai',
    },
    {
      enabled: false,
      name: 'Evening — switch to Personal workspace',
      description: 'Switches to your Personal workspace after 18:00 local time.',
      triggerType: 'time_window',
      triggerValue: '18:00-23:59',
      actionType: 'switch_workspace',
      actionValue: '',
    },
    {
      enabled: false,
      name: 'Block social media distractions',
      description: 'Blocks twitter.com / x.com from loading. Enable when you need to focus.',
      triggerType: 'url_contains',
      triggerValue: 'twitter.com',
      actionType: 'block_hostname',
      actionValue: 'twitter.com',
    },
    {
      enabled: false,
      name: 'YouTube — block autoplay',
      description: 'Runs JS to pause autoplay on YouTube pages.',
      triggerType: 'url_contains',
      triggerValue: 'youtube.com',
      actionType: 'run_javascript',
      actionValue: 'document.querySelector("video")?.pause();',
    },
  ];

  async installMarketplaceRule(mr: (typeof this.marketplaceRules)[number]): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const r: AutomationRuleDTO = {
      ...mr,
      id: crypto.randomUUID(),
    };
    await this.persisted.patch({ automationRules: [...snap.automationRules, r] });
    this.toast.show(`"${mr.name}" installed.`);
  }

  ruleTimeStart(triggerValue: string): string {
    return (triggerValue ?? '').split('-')[0] ?? '09:00';
  }

  ruleTimeEnd(triggerValue: string): string {
    return (triggerValue ?? '').split('-')[1] ?? '17:00';
  }

  /** @deprecated kept for any legacy callers; use installMarketplaceRule instead. */
  async addAutomationPresetRules(): Promise<void> {
    await this.installMarketplaceRule(this.marketplaceRules[0]);
  }

  setFontSize(v: number): void {
    if (v === 12 || v === 14 || v === 16) void this.patchSettings({ fontSize: v });
  }

  setAiProvider(v: string): void {
    if (v === 'mock' || v === 'openai') void this.patchSettings({ aiProvider: v });
  }

  setThemePreset(v: string): void {
    const allowed = ['dark', 'light', 'midnight', 'solarized', 'high-contrast'] as const;
    type T = (typeof allowed)[number];
    if ((allowed as readonly string[]).includes(v))
      void this.patchSettings({ themePreset: v as T });
  }

  async addAutofillHint(): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const h: AutofillHintDTO = {
      id: crypto.randomUUID(),
      label: 'New hint',
      value: '',
    };
    await this.patchSettings({ autofillHints: [...(snap.settings.autofillHints ?? []), h] });
  }

  async updateAutofillHint(id: string, patch: Partial<AutofillHintDTO>): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const next = (snap.settings.autofillHints ?? []).map((x) =>
      x.id === id ? { ...x, ...patch } : x,
    );
    await this.patchSettings({ autofillHints: next });
  }

  async removeAutofillHint(id: string): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    await this.patchSettings({
      autofillHints: (snap.settings.autofillHints ?? []).filter((x) => x.id !== id),
    });
  }

  exportCompanionSnapshot(): void {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const payload: CompanionSnapshotV1 = {
      companion: COMPANION_SNAPSHOT_VERSION,
      exportedAt: Date.now(),
      app: 'dev-lens',
      bookmarks: snap.bookmarks.map((b) => ({ url: b.url, title: b.title })),
      readLater: snap.readLater.map((r) => ({ url: r.url, title: r.title, addedAt: r.addedAt })),
      sessions: snap.savedSessions.map((s) => ({
        name: s.name,
        savedAt: s.savedAt,
        tabs: s.tabs,
      })),
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-companion-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  openBackupExportModal(): void {
    this.backupExportPass.set('');
    this.backupExportPass2.set('');
    this.backupExportOpen.set(true);
  }

  closeBackupExportModal(): void {
    this.backupExportOpen.set(false);
  }

  onModalBackdropKeydown(
    ev: KeyboardEvent,
    target: 'backup-export' | 'backup-import' | 'reset-data' | 'shortcuts-reset',
  ): void {
    if (ev.key !== 'Enter' && ev.key !== ' ') return;
    ev.preventDefault();
    switch (target) {
      case 'backup-export':
        this.closeBackupExportModal();
        break;
      case 'backup-import':
        this.cancelBackupImport();
        break;
      case 'reset-data':
        this.cancelResetData();
        break;
      case 'shortcuts-reset':
        this.cancelShortcutsReset();
        break;
    }
  }

  async submitBackupExport(): Promise<void> {
    const pass = this.backupExportPass().trim();
    const pass2 = this.backupExportPass2().trim();
    if (pass.length < 8) {
      this.toast.error('Passphrase must be at least 8 characters.');
      return;
    }
    if (pass !== pass2) {
      this.toast.error('Passphrases do not match.');
      return;
    }
    const snap = this.persisted.snapshot();
    if (!snap) return;
    this.backupExportOpen.set(false);
    const payload = {
      bookmarks: snap.bookmarks,
      notes: snap.notes,
      readLater: snap.readLater,
      workspaces: snap.workspaces,
      activeWorkspaceId: snap.activeWorkspaceId,
      settings: snap.settings,
      savedSessions: snap.savedSessions,
      automationRules: snap.automationRules,
      tabGroups: snap.tabGroups,
      openTabs: snap.openTabs,
      clipboardHistory: snap.clipboardHistory,
      history: snap.history,
      pluginStates: snap.pluginStates,
      pluginStorage: snap.pluginStorage,
    };
    try {
      const json = await this.backupCrypto.encryptJson(payload, pass);
      const blob = new Blob([json], { type: 'application/json' });
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = `dev-lens-backup-${Date.now()}.json`;
      a.click();
      URL.revokeObjectURL(a.href);
      await this.patchSettings({ lastEncryptedBackupAt: new Date().toISOString() });
      this.toast.show('Encrypted backup file saved.');
    } catch (e) {
      this.toast.error(e instanceof Error ? e.message : 'Export failed.');
    }
  }

  cancelBackupImport(): void {
    this.backupImportOpen.set(false);
    this.backupImportJson.set(null);
    this.backupImportPass.set('');
    this.backupImportStep.set('pass');
    this.backupImportDecoded.set(null);
  }

  async backupImportDecryptStep(): Promise<void> {
    const json = this.backupImportJson();
    const pass = this.backupImportPass().trim();
    if (!json || !pass) {
      this.toast.error('Enter your passphrase.');
      return;
    }
    try {
      const data = await this.backupCrypto.decryptJson<BackupImportPayload>(json, pass);
      this.backupImportDecoded.set(data);
      this.backupImportStep.set('confirm');
    } catch (e) {
      this.toast.error(e instanceof Error ? e.message : 'Could not decrypt backup.');
    }
  }

  async applyBackupImport(): Promise<void> {
    const data = this.backupImportDecoded();
    const cur = this.persisted.snapshot();
    if (!data || !cur) return;
    const mode = cur.settings.encryptedImportMode ?? 'replace';
    try {
      if (mode === 'merge_lww') {
        const patch: Partial<DevLensStoreSnapshot> = {};
        if (data.bookmarks) patch.bookmarks = mergeBookmarksLww(cur.bookmarks, data.bookmarks);
        if (data.notes) patch.notes = mergeNotesLww(cur.notes, data.notes);
        if (data.readLater) patch.readLater = mergeReadLaterLww(cur.readLater, data.readLater);
        if (data.savedSessions)
          patch.savedSessions = mergeSavedSessionsLww(cur.savedSessions, data.savedSessions);
        if (data.automationRules)
          patch.automationRules = mergeAutomationRulesLww(
            cur.automationRules,
            data.automationRules,
          );
        if (data.clipboardHistory)
          patch.clipboardHistory = mergeClipboardLww(cur.clipboardHistory, data.clipboardHistory);
        if (data.workspaces) patch.workspaces = mergeWorkspacesLww(cur.workspaces, data.workspaces);
        if (data.pluginStates)
          patch.pluginStates = mergePluginStatesLww(cur.pluginStates ?? {}, data.pluginStates);
        if (data.pluginStorage)
          patch.pluginStorage = mergePluginStorageLww(cur.pluginStorage ?? {}, data.pluginStorage);
        await this.persisted.patch(patch);
      } else {
        await this.persisted.patch({
          ...(data.bookmarks ? { bookmarks: data.bookmarks } : {}),
          ...(data.notes ? { notes: data.notes } : {}),
          ...(data.readLater ? { readLater: data.readLater } : {}),
          ...(data.workspaces ? { workspaces: data.workspaces } : {}),
          ...(data.activeWorkspaceId ? { activeWorkspaceId: data.activeWorkspaceId } : {}),
          ...(data.settings ? { settings: data.settings } : {}),
          ...(data.savedSessions ? { savedSessions: data.savedSessions } : {}),
          ...(data.automationRules ? { automationRules: data.automationRules } : {}),
          ...(data.tabGroups ? { tabGroups: data.tabGroups } : {}),
          ...(data.openTabs ? { openTabs: data.openTabs } : {}),
          ...(data.clipboardHistory ? { clipboardHistory: data.clipboardHistory } : {}),
          ...(data.history ? { history: data.history } : {}),
          ...(data.pluginStates ? { pluginStates: data.pluginStates } : {}),
          ...(data.pluginStorage ? { pluginStorage: data.pluginStorage } : {}),
        });
      }
      this.cancelBackupImport();
      this.toast.show('Backup imported successfully.');
    } catch (e) {
      this.toast.error(e instanceof Error ? e.message : 'Import failed.');
    }
  }

  async loadExtensions(): Promise<void> {
    if (!this.bridge.isElectron) return;
    this.extLoading.set(true);
    try {
      const list = await this.bridge.invoke<InstalledExtensionInfo[]>(IPC_CHANNELS.EXT_LIST);
      this.installedExtensions.set(Array.isArray(list) ? list : []);
    } finally {
      this.extLoading.set(false);
    }
  }

  async removeExtension(id: string, name: string): Promise<void> {
    if (
      !confirm(`Remove "${name}" from Dev-Lens? The app will need to restart to fully unload it.`)
    )
      return;
    const r = await this.bridge.invoke<{ ok: boolean; error?: string }>(IPC_CHANNELS.EXT_REMOVE, {
      extensionId: id,
    });
    if (r.ok) {
      this.toast.show(`"${name}" removed. Restart Dev-Lens to fully unload it.`);
      await this.loadExtensions();
    } else {
      this.toast.error(r.error ?? 'Remove failed.');
    }
  }

  onImportEncryptedBackupPick(ev: Event): void {
    const input = ev.target as HTMLInputElement;
    const file = input.files?.[0];
    input.value = '';
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      this.backupImportJson.set(reader.result as string);
      this.backupImportPass.set('');
      this.backupImportStep.set('pass');
      this.backupImportDecoded.set(null);
      this.backupImportOpen.set(true);
    };
    reader.readAsText(file);
  }
}

import {
  Component,
  computed,
  inject,
  signal,
  ElementRef,
  viewChild,
  AfterViewChecked,
  OnDestroy,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Subscription } from 'rxjs';
import { PageAiIntentService } from '@core/services/page-ai-intent.service';
import { PersistedStateService } from '@core/services/persisted-state.service';
import { TabsService } from '@core/services/tabs.service';

interface ChatMessage {
  role: 'bot' | 'user';
  text: string;
}

const CANNED: Record<string, string> = {
  summarize:
    'Sure! This page appears to be about web development. Key points: modern frameworks, component-based architecture, and reactive data flow.',
  help: 'I can summarize pages, answer questions about content, or assist with research. Just ask!',
  default:
    "I'm a local AI assistant. I can help analyze the current page, answer questions, or assist with research tasks.",
};

function pickResponse(input: string): string {
  const q = input.toLowerCase();
  if (q.includes('summar') || q.includes('what is this')) return CANNED['summarize'];
  if (q.includes('help') || q.includes('what can you')) return CANNED['help'];
  return CANNED['default'];
}

/** RAG-lite: pull several body text chunks from the active page for AI context. */
const PAGE_CONTEXT_CHUNK = 1400;
const PAGE_CONTEXT_MAX_CHUNKS = 5;
const PAGE_CONTEXT_SCRIPT = `(function(){
  var t=document.title||'';
  var b=document.body&&document.body.innerText?document.body.innerText:'';
  var max=${PAGE_CONTEXT_CHUNK};
  var cap=${PAGE_CONTEXT_MAX_CHUNKS};
  var chunks=[];
  for(var i=0;i<b.length&&chunks.length<cap;i+=max){chunks.push(b.slice(i,i+max));}
  return JSON.stringify({title:t,chunks:chunks});
})()`;

function formatPageContextForAi(raw: string): string {
  try {
    const o = JSON.parse(raw) as { title?: string; chunks?: string[] };
    const title = o.title?.trim() || '(untitled)';
    const parts = (o.chunks ?? []).filter((c) => c?.trim());
    if (!parts.length) return title + ' — (no body text)';
    return (
      title +
      '\n\n' +
      parts.map((c, i) => '[Chunk ' + (i + 1) + '/' + parts.length + ']\n' + c.trim()).join('\n\n')
    );
  } catch {
    return raw.slice(0, 6000);
  }
}

@Component({
  selector: 'app-ai-widget',
  imports: [FormsModule],
  templateUrl: './ai-widget.component.html',
  styleUrl: './ai-widget.component.scss',
})
export class AiWidgetComponent implements AfterViewChecked, OnDestroy {
  private readonly tabs = inject(TabsService);
  private readonly persisted = inject(PersistedStateService);
  private readonly pageAi = inject(PageAiIntentService);
  private readonly scrollRef = viewChild<ElementRef<HTMLElement>>('scroll');
  private intentSub: Subscription | undefined;

  readonly messages = signal<ChatMessage[]>([
    {
      role: 'bot',
      text: 'Hi! I can help you summarize pages, answer questions about content, or assist with research. What would you like to know?',
    },
  ]);
  readonly input = signal('');
  readonly loading = signal(false);

  /** Matches `runCompletion`: real API only when OpenAI + API key. */
  readonly showDemoBanner = computed(() => {
    const s = this.persisted.snapshot()?.settings;
    if (!s) return true;
    return s.aiProvider !== 'openai' || (s.aiApiKey?.trim()?.length ?? 0) === 0;
  });

  private lastScrollLen = 0;

  constructor() {
    this.intentSub = this.pageAi.intents$.subscribe((text) => {
      void this.runCompletion(text);
    });
  }

  ngOnDestroy(): void {
    this.intentSub?.unsubscribe();
  }

  ngAfterViewChecked(): void {
    const msgs = this.messages();
    if (msgs.length !== this.lastScrollLen) {
      this.lastScrollLen = msgs.length;
      const el = this.scrollRef()?.nativeElement;
      if (el) el.scrollTop = el.scrollHeight;
    }
  }

  openAiSettings(): void {
    void this.tabs.addInternalTab('settings', 'Settings');
  }

  async send(): Promise<void> {
    const text = this.input().trim();
    if (!text) return;
    this.input.set('');
    await this.runCompletion(text);
  }

  private async runCompletion(userText: string): Promise<void> {
    this.messages.update((m) => [...m, { role: 'user', text: userText }]);
    this.loading.set(true);

    let context = '';
    try {
      const raw = (await this.tabs.executeJavaScriptInActive(PAGE_CONTEXT_SCRIPT)) as string;
      context = formatPageContextForAi(typeof raw === 'string' ? raw : '');
    } catch {
      /* ignore */
    }

    const settings = this.persisted.snapshot()?.settings;
    const useOpenAi =
      settings?.aiProvider === 'openai' && (settings.aiApiKey?.trim()?.length ?? 0) > 0;

    try {
      if (useOpenAi && settings) {
        const base = (settings.aiBaseUrl?.trim() || 'https://api.openai.com/v1').replace(/\/$/, '');
        const model = settings.aiModel?.trim() || 'gpt-4o-mini';
        const thread = this.messages()
          .slice(1)
          .map((msg) => ({
            role: msg.role === 'user' ? ('user' as const) : ('assistant' as const),
            content: msg.text,
          }));
        const res = await fetch(`${base}/chat/completions`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${settings.aiApiKey.trim()}`,
          },
          body: JSON.stringify({
            model,
            messages: [
              {
                role: 'system',
                content:
                  'You are a concise assistant inside a desktop browser. Use the page context when relevant. Keep answers brief unless the user asks for detail.\n\nPage context:\n' +
                  (context || '(no page context)'),
              },
              ...thread.slice(-14),
            ],
          }),
        });
        const data = (await res.json()) as {
          error?: { message?: string };
          choices?: { message?: { content?: string } }[];
        };
        if (!res.ok) {
          const err = data.error?.message ?? `HTTP ${res.status}`;
          this.messages.update((m) => [...m, { role: 'bot', text: `Error: ${err}` }]);
        } else {
          const reply = data.choices?.[0]?.message?.content?.trim() || '(empty response)';
          this.messages.update((m) => [...m, { role: 'bot', text: reply }]);
        }
      } else {
        await new Promise((r) => setTimeout(r, 400));
        const response = context
          ? `Based on page context: ${pickResponse(userText)}`
          : pickResponse(userText);
        this.messages.update((m) => [...m, { role: 'bot', text: response }]);
      }
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      this.messages.update((m) => [...m, { role: 'bot', text: `Request failed: ${msg}` }]);
    } finally {
      this.loading.set(false);
    }
  }
}

import {
  Component,
  DestroyRef,
  ElementRef,
  computed,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { NgTemplateOutlet } from '@angular/common';
import { GuestLogService, type GuestConsoleLine } from '@core/services/guest-log.service';
import { ResizeStateService } from '@core/services/resize-state.service';
import { FeatureFlagsService } from '@core/services/feature-flags.service';
import { TabsService } from '@core/services/tabs.service';
import { ElectronBridgeService } from '@core/services/electron-bridge.service';
import { RENDERER_INVOKE } from '@core/electron-ipc-channels';

type DisplayLevel = 'info' | 'warn' | 'error' | 'result';
type PanelTab = 'console' | 'network' | 'elements' | 'sources' | 'performance';

interface ConsoleDisplayLine {
  level: DisplayLevel;
  text: string;
  time: string;
}

export interface DomNode {
  tag: string;
  id: string;
  classes: string;
  children: DomNode[];
  textSnippet: string;
}

export interface SourceEntry {
  name: string;
  type: string;
  size: number;
  duration: number;
}

export interface PerfMetrics {
  loadMs: number | null;
  domReadyMs: number | null;
  resources: number;
  scripts: number;
  memUsed: number | null;
  memTotal: number | null;
  paint: { name: string; time: number }[];
  lcp: number | null;
}

export const NETWORK_RESOURCE_FILTER_OPTIONS: { value: string; label: string }[] = [
  { value: 'all', label: 'All types' },
  { value: 'xhr', label: 'XHR' },
  { value: 'mainFrame', label: 'Document' },
  { value: 'subFrame', label: 'Subframe' },
  { value: 'script', label: 'Script' },
  { value: 'stylesheet', label: 'Stylesheet' },
  { value: 'image', label: 'Image' },
  { value: 'font', label: 'Font' },
  { value: 'media', label: 'Media' },
  { value: 'webSocket', label: 'WebSocket' },
  { value: 'ping', label: 'Ping' },
  { value: 'cspReport', label: 'CSP report' },
  { value: 'object', label: 'Object' },
  { value: 'other', label: 'Other' },
];

const DOM_SNAPSHOT_JS = `(function(){
  function snap(el, depth){
    if(!el||depth>4) return null;
    var cs=Array.from(el.children).slice(0,12).map(function(c){return snap(c,depth+1);}).filter(Boolean);
    var txt=el.children.length===0?(el.textContent||'').trim().slice(0,60):'';
    return {tag:(el.tagName||'').toLowerCase(),id:el.id||'',classes:(el.className&&typeof el.className==='string'?el.className.trim().split(/\\s+/).slice(0,3).join(' '):''),children:cs,textSnippet:txt};
  }
  return JSON.stringify(snap(document.body,0));
})()`;

const SOURCES_JS = `(function(){
  try{
    var entries=performance.getEntriesByType('resource');
    return JSON.stringify(entries.slice(0,80).map(function(e){
      return {name:e.name,type:e.initiatorType,size:Math.round(e.transferSize||0),duration:Math.round(e.duration)};
    }));
  }catch(ex){return '[]';}
})()`;

const PERF_JS = `(function(){
  var t=window.performance.timing||null;
  var entries=performance.getEntriesByType('resource');
  var paint=performance.getEntriesByType('paint').map(function(e){return {name:e.name,time:Math.round(e.startTime)};});
  var lcp=null;
  try{ if(typeof window.__devLensLcp==='number') lcp=Math.round(window.__devLensLcp); }catch(e){}
  return JSON.stringify({
    loadMs:t?(t.loadEventEnd-t.navigationStart)||null:null,
    domReadyMs:t?(t.domContentLoadedEventEnd-t.navigationStart)||null:null,
    resources:entries.length,
    scripts:entries.filter(function(e){return e.initiatorType==='script';}).length,
    memUsed:performance.memory?performance.memory.usedJSHeapSize:null,
    memTotal:performance.memory?performance.memory.totalJSHeapSize:null,
    paint:paint,lcp:lcp
  });
})()`;

function formatTime(t: number): string {
  return new Date(t).toLocaleTimeString('en-US', { hour12: false });
}

function guestToDisplayLevel(line: GuestConsoleLine): DisplayLevel {
  if (line.source === 'repl')
    return line.level === 'error' ? 'error' : line.level === 'result' ? 'result' : 'info';
  if (line.level === 'warn') return 'warn';
  if (line.level === 'error') return 'error';
  return 'info';
}

function fmtBytes(b: number | null): string {
  if (b === null) return '—';
  if (b < 1024) return `${b} B`;
  if (b < 1024 * 1024) return `${(b / 1024).toFixed(1)} KB`;
  return `${(b / 1024 / 1024).toFixed(1)} MB`;
}

type DtStatus = 'idle' | 'attaching' | 'attached' | 'no-tab' | 'error';

@Component({
  selector: 'app-console-widget',
  imports: [FormsModule, NgTemplateOutlet],
  templateUrl: './console-widget.component.html',
  styleUrl: './console-widget.component.scss',
})
export class ConsoleWidgetComponent {
  private readonly tabs = inject(TabsService);
  private readonly features = inject(FeatureFlagsService);
  readonly bridge = inject(ElectronBridgeService);
  private readonly destroyRef = inject(DestroyRef);
  readonly guestLog = inject(GuestLogService);
  private readonly resizeState = inject(ResizeStateService);

  /** Container div that marks where the BrowserView overlay should sit. */
  private readonly dtAreaRef = viewChild<ElementRef>('dtArea');

  /** Whether the currently active tab is a browser tab (has a guest webview). */
  readonly activeBrowserTabId = computed(() => {
    const tab = this.tabs.activeTab();
    return tab?.kind === 'browser' ? tab.id : null;
  });

  readonly dtStatus = signal<DtStatus>('idle');
  readonly dtError = signal<string | null>(null);

  /** WebContentsId of the guest we currently have DevTools attached to. */
  private lastGuestWcId: number | null = null;

  private resizeObserver: ResizeObserver | null = null;
  private intersectionObserver: IntersectionObserver | null = null;

  readonly activeTab = signal<PanelTab>('console');
  readonly command = signal('');

  readonly consoleLines = computed<ConsoleDisplayLine[]>(() =>
    this.guestLog.filteredConsole().map((l) => ({
      level: guestToDisplayLevel(l),
      text: l.msg,
      time: formatTime(l.t),
    })),
  );

  readonly networkLines = this.guestLog.filteredNetwork;
  readonly networkUrlFilter = signal('');
  readonly filteredNetworkLines = computed(() => {
    const q = this.networkUrlFilter().trim().toLowerCase();
    const rows = this.networkLines();
    return q ? rows.filter((r) => r.url.toLowerCase().includes(q)) : rows;
  });
  readonly netFilterOptions = NETWORK_RESOURCE_FILTER_OPTIONS;

  readonly domTree = signal<DomNode | null>(null);
  readonly domLoading = signal(false);
  readonly sourcesEntries = signal<SourceEntry[]>([]);
  readonly sourcesLoading = signal(false);
  readonly perfMetrics = signal<PerfMetrics | null>(null);
  readonly perfLoading = signal(false);

  readonly fmtBytes = fmtBytes;

  constructor() {
    if (this.bridge.isElectron) {
      this.setupElectronDevTools();
    }

    // Detach cleanly when the component is destroyed.
    this.destroyRef.onDestroy(() => {
      this.teardownObservers();
      void this.detachDevTools();
    });

    // Refresh custom panel data when switching tabs (non-Electron fallback).
    effect(() => {
      if (this.bridge.isElectron) return;
      const tab = this.activeTab();
      if (tab === 'elements') void this.refreshElements();
      else if (tab === 'sources') void this.refreshSources();
      else if (tab === 'performance') void this.refreshPerf();
    });
  }

  private setupElectronDevTools(): void {
    let prevBrowserTabId: string | null = null;

    // React to active-tab changes: detach the old DevTools and re-attach for the
    // new tab. The actual DEVTOOLS_ATTACH IPC is deferred until the #dtArea div
    // is in the DOM and has non-zero dimensions.
    effect(() => {
      const id = this.activeBrowserTabId();
      if (id === prevBrowserTabId) return;
      prevBrowserTabId = id;

      void this.detachDevTools();

      if (id === null) {
        this.dtStatus.set('no-tab');
      } else {
        this.dtStatus.set('attaching');
        this.dtError.set(null);
        // dtArea may not be in the DOM yet (first render); retry until visible.
        void this.attachWhenReady();
      }
    });

    // When #dtArea appears or disappears, wire up / tear down the observers that
    // keep the BrowserView overlay in sync with the element's position & size.
    effect(() => {
      const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
      if (el) {
        this.setupObservers(el);
      } else {
        this.teardownObservers();
      }
    });

    // Register synchronous hide/restore callbacks with ResizeStateService.
    // These fire IMMEDIATELY inside onResizeDown / onResizeUp in the
    // right-sidebar component — before any mousemove can reach the
    // BrowserView overlay and steal pointer events.
    this.resizeState.registerOverlayCallbacks(
      // hide — called synchronously on mousedown
      () => {
        if (this.lastGuestWcId !== null) this.hideOverlay();
      },
      // restore — called synchronously on mouseup; rAF lets the browser
      // finish painting the sidebar at its final width before we read bounds.
      () => {
        if (this.lastGuestWcId !== null) {
          requestAnimationFrame(() => {
            const bounds = this.getDtBounds();
            if (bounds) void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
          });
        }
      },
    );
  }

  // ── BrowserView overlay helpers ─────────────────────────────────────────────

  private getDtBounds(): { x: number; y: number; width: number; height: number } | null {
    const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
    if (!el) return null;
    const r = el.getBoundingClientRect();
    if (r.width < 4 || r.height < 4) return null;
    return {
      x: Math.round(r.left),
      y: Math.round(r.top),
      width: Math.round(r.width),
      height: Math.round(r.height),
    };
  }

  /** Try to attach DevTools, retrying with rAF if the area isn't rendered yet. */
  private async attachWhenReady(attempt = 0): Promise<void> {
    const bounds = this.getDtBounds();
    if (!bounds) {
      if (attempt < 60) {
        await new Promise<void>((res) => requestAnimationFrame(() => res()));
        return this.attachWhenReady(attempt + 1);
      }
      // After ~1s of retries still no bounds — leave status as 'attaching' so
      // the IntersectionObserver can recover when the panel becomes visible.
      return;
    }
    await this.attachDevTools(bounds);
  }

  private async attachDevTools(bounds: {
    x: number;
    y: number;
    width: number;
    height: number;
  }): Promise<void> {
    const guestWcId = this.tabs.getActiveGuestWcId();
    if (!guestWcId) {
      this.dtStatus.set('no-tab');
      return;
    }

    this.lastGuestWcId = guestWcId;

    const res = await this.bridge.invoke<{ ok: boolean; error?: string }>(
      RENDERER_INVOKE.DEVTOOLS_ATTACH,
      { guestWcId, bounds },
    );

    if (res.ok) {
      this.dtStatus.set('attached');
      this.dtError.set(null);
    } else {
      this.dtStatus.set('error');
      this.dtError.set(res.error ?? 'Failed to attach DevTools.');
      this.lastGuestWcId = null;
    }
  }

  private async detachDevTools(): Promise<void> {
    const wcId = this.lastGuestWcId;
    this.lastGuestWcId = null;
    if (wcId !== null) {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, { guestWcId: wcId });
    } else {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, {});
    }
  }

  /** Reposition the overlay to match the current #dtArea bounds. */
  private updateBounds(): void {
    if (this.lastGuestWcId === null) return;
    if (this.resizeState.isSidebarResizing()) return;
    const bounds = this.getDtBounds();
    if (bounds) {
      void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
    }
  }

  /** Move overlay off-screen without detaching the DevTools connection. */
  private hideOverlay(): void {
    void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, {
      bounds: { x: -32000, y: -32000, width: 1, height: 1 },
    });
  }

  private setupObservers(el: HTMLElement): void {
    this.teardownObservers();

    // Keep overlay in sync when the element resizes (e.g. sidebar width changes).
    this.resizeObserver = new ResizeObserver(() => this.updateBounds());
    this.resizeObserver.observe(el);

    // Hide/show the BrowserView overlay when the element scrolls out of view
    // (e.g. user collapses the right sidebar).
    this.intersectionObserver = new IntersectionObserver(
      (entries) => {
        const visible = entries.some((e) => e.isIntersecting);
        if (visible) {
          if (this.lastGuestWcId !== null) {
            this.updateBounds();
          } else if (this.activeBrowserTabId() !== null) {
            void this.attachWhenReady();
          }
        } else {
          this.hideOverlay();
        }
      },
      { threshold: 0.01 },
    );
    this.intersectionObserver.observe(el);

    // Also handle window-level resize (position may shift even if element size stays the same).
    const onWindowResize = (): void => this.updateBounds();
    window.addEventListener('resize', onWindowResize);
    this.destroyRef.onDestroy(() => window.removeEventListener('resize', onWindowResize));
  }

  private teardownObservers(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;
    this.intersectionObserver?.disconnect();
    this.intersectionObserver = null;
  }

  // ── Non-Electron fallback helpers ──────────────────────────────────────────

  async refreshElements(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.domLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(DOM_SNAPSHOT_JS);
      this.domTree.set(raw ? (JSON.parse(raw as string) as DomNode) : null);
    } catch {
      this.domTree.set(null);
    } finally {
      this.domLoading.set(false);
    }
  }

  async refreshSources(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.sourcesLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(SOURCES_JS);
      this.sourcesEntries.set(raw ? (JSON.parse(raw as string) as SourceEntry[]) : []);
    } catch {
      this.sourcesEntries.set([]);
    } finally {
      this.sourcesLoading.set(false);
    }
  }

  async refreshPerf(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.perfLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(PERF_JS);
      this.perfMetrics.set(raw ? (JSON.parse(raw as string) as PerfMetrics) : null);
    } catch {
      this.perfMetrics.set(null);
    } finally {
      this.perfLoading.set(false);
    }
  }

  async runCommand(): Promise<void> {
    const code = this.command().trim();
    const tabId = this.tabs.activeTabId();
    if (!code || !tabId) return;
    this.command.set('');
    this.guestLog.pushRepl(tabId, 'info', `> ${code}`);
    try {
      const result = await this.tabs.executeJavaScriptInActive(code);
      const text = result === undefined ? 'undefined' : JSON.stringify(result, null, 2);
      this.guestLog.pushRepl(tabId, 'result', text);
    } catch (err) {
      this.guestLog.pushRepl(tabId, 'error', err instanceof Error ? err.message : String(err));
    }
  }

  openNativeDevTools(): void {
    if (!this.features.mode('devtools')) return;
    void this.tabs.toggleDevtools();
  }

  clearPanel(): void {
    if (this.activeTab() === 'console') this.guestLog.clearConsoleForActiveTab();
    else if (this.activeTab() === 'network') this.guestLog.clearNetworkForActivePartition();
  }

  exportHar(): void {
    const json = this.guestLog.exportHarForActivePartition();
    const blob = new Blob([json], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-network-${Date.now()}.har`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  statusClass(code: number): string {
    if (code >= 200 && code < 300) return 'con__net-status--2';
    if (code >= 300 && code < 400) return 'con__net-status--3';
    if (code >= 400 && code < 500) return 'con__net-status--4';
    if (code >= 500) return 'con__net-status--5';
    return 'con__net-status--0';
  }

  netTimeLabel(t: number): string {
    const d = new Date(t);
    const pad = (n: number, w = 2): string => String(n).padStart(w, '0');
    return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad(d.getMilliseconds(), 3)}`;
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { IPC_CHANNELS } from '@dev-lens/shared';
import { ElectronBridgeService } from './electron-bridge.service';

export interface DiscoveredPluginUi {
  id: string;
  name: string;
  version: string;
  permissions: string[];
  sidebarTitle: string;
  entryBaseUrl: string;
  bundled: boolean;
  enabled: boolean;
}

@Injectable({ providedIn: 'root' })
export class PluginRuntimeService {
  private readonly bridge = inject(ElectronBridgeService);

  /** Plugins that are enabled (shown in sidebar). */
  readonly sidebarPlugins = signal<DiscoveredPluginUi[]>([]);
  /** Full discovery list (Settings UI). */
  readonly allPlugins = signal<DiscoveredPluginUi[]>([]);

  async refresh(): Promise<void> {
    if (!this.bridge.isElectron) {
      this.sidebarPlugins.set([]);
      this.allPlugins.set([]);
      return;
    }
    const r = await this.bridge.invoke<{ plugins: DiscoveredPluginUi[] }>(
      IPC_CHANNELS.PLUGIN_DISCOVER,
    );
    const list = r.plugins ?? [];
    this.allPlugins.set(list);
    this.sidebarPlugins.set(list.filter((p) => p.enabled));
  }

  async setEnabled(id: string, enabled: boolean): Promise<void> {
    if (!this.bridge.isElectron) return;
    const res = await this.bridge.invoke<{ ok?: boolean }>(IPC_CHANNELS.PLUGIN_SET_ENABLED, {
      id,
      enabled,
    });
    if (res && typeof res === 'object' && 'ok' in res && res.ok === false) return;
    await this.refresh();
  }
}

import {
  Component,
  DestroyRef,
  ElementRef,
  computed,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { NgTemplateOutlet } from '@angular/common';
import { GuestLogService, type GuestConsoleLine } from '@core/services/guest-log.service';
import { ResizeStateService } from '@core/services/resize-state.service';
import { FeatureFlagsService } from '@core/services/feature-flags.service';
import { TabsService } from '@core/services/tabs.service';
import { ElectronBridgeService } from '@core/services/electron-bridge.service';
import { RENDERER_INVOKE } from '@core/electron-ipc-channels';

type DisplayLevel = 'info' | 'warn' | 'error' | 'result';
type PanelTab = 'console' | 'network' | 'elements' | 'sources' | 'performance';

interface ConsoleDisplayLine {
  level: DisplayLevel;
  text: string;
  time: string;
}

export interface DomNode {
  tag: string;
  id: string;
  classes: string;
  children: DomNode[];
  textSnippet: string;
}

export interface SourceEntry {
  name: string;
  type: string;
  size: number;
  duration: number;
}

export interface PerfMetrics {
  loadMs: number | null;
  domReadyMs: number | null;
  resources: number;
  scripts: number;
  memUsed: number | null;
  memTotal: number | null;
  paint: { name: string; time: number }[];
  lcp: number | null;
}

export const NETWORK_RESOURCE_FILTER_OPTIONS: { value: string; label: string }[] = [
  { value: 'all', label: 'All types' },
  { value: 'xhr', label: 'XHR' },
  { value: 'mainFrame', label: 'Document' },
  { value: 'subFrame', label: 'Subframe' },
  { value: 'script', label: 'Script' },
  { value: 'stylesheet', label: 'Stylesheet' },
  { value: 'image', label: 'Image' },
  { value: 'font', label: 'Font' },
  { value: 'media', label: 'Media' },
  { value: 'webSocket', label: 'WebSocket' },
  { value: 'ping', label: 'Ping' },
  { value: 'cspReport', label: 'CSP report' },
  { value: 'object', label: 'Object' },
  { value: 'other', label: 'Other' },
];

const DOM_SNAPSHOT_JS = `(function(){
  function snap(el, depth){
    if(!el||depth>4) return null;
    var cs=Array.from(el.children).slice(0,12).map(function(c){return snap(c,depth+1);}).filter(Boolean);
    var txt=el.children.length===0?(el.textContent||'').trim().slice(0,60):'';
    return {tag:(el.tagName||'').toLowerCase(),id:el.id||'',classes:(el.className&&typeof el.className==='string'?el.className.trim().split(/\\s+/).slice(0,3).join(' '):''),children:cs,textSnippet:txt};
  }
  return JSON.stringify(snap(document.body,0));
})()`;

const SOURCES_JS = `(function(){
  try{
    var entries=performance.getEntriesByType('resource');
    return JSON.stringify(entries.slice(0,80).map(function(e){
      return {name:e.name,type:e.initiatorType,size:Math.round(e.transferSize||0),duration:Math.round(e.duration)};
    }));
  }catch(ex){return '[]';}
})()`;

const PERF_JS = `(function(){
  var t=window.performance.timing||null;
  var entries=performance.getEntriesByType('resource');
  var paint=performance.getEntriesByType('paint').map(function(e){return {name:e.name,time:Math.round(e.startTime)};});
  var lcp=null;
  try{ if(typeof window.__devLensLcp==='number') lcp=Math.round(window.__devLensLcp); }catch(e){}
  return JSON.stringify({
    loadMs:t?(t.loadEventEnd-t.navigationStart)||null:null,
    domReadyMs:t?(t.domContentLoadedEventEnd-t.navigationStart)||null:null,
    resources:entries.length,
    scripts:entries.filter(function(e){return e.initiatorType==='script';}).length,
    memUsed:performance.memory?performance.memory.usedJSHeapSize:null,
    memTotal:performance.memory?performance.memory.totalJSHeapSize:null,
    paint:paint,lcp:lcp
  });
})()`;

function formatTime(t: number): string {
  return new Date(t).toLocaleTimeString('en-US', { hour12: false });
}

function guestToDisplayLevel(line: GuestConsoleLine): DisplayLevel {
  if (line.source === 'repl')
    return line.level === 'error' ? 'error' : line.level === 'result' ? 'result' : 'info';
  if (line.level === 'warn') return 'warn';
  if (line.level === 'error') return 'error';
  return 'info';
}

function fmtBytes(b: number | null): string {
  if (b === null) return '—';
  if (b < 1024) return `${b} B`;
  if (b < 1024 * 1024) return `${(b / 1024).toFixed(1)} KB`;
  return `${(b / 1024 / 1024).toFixed(1)} MB`;
}

type DtStatus = 'idle' | 'attaching' | 'attached' | 'no-tab' | 'error';

@Component({
  selector: 'app-console-widget',
