    try {
      const result = await this.tabs.executeJavaScriptInActive(code);
      const text = result === undefined ? 'undefined' : JSON.stringify(result, null, 2);
      this.guestLog.pushRepl(tabId, 'result', text);
    } catch (err) {
      this.guestLog.pushRepl(tabId, 'error', err instanceof Error ? err.message : String(err));
    }
  }

  openNativeDevTools(): void {
    if (!this.features.mode('devtools')) return;
    void this.tabs.toggleDevtools();
  }

  clearPanel(): void {
    if (this.activeTab() === 'console') this.guestLog.clearConsoleForActiveTab();
    else if (this.activeTab() === 'network') this.guestLog.clearNetworkForActivePartition();
  }

  exportHar(): void {
    const json = this.guestLog.exportHarForActivePartition();
    const blob = new Blob([json], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-network-${Date.now()}.har`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  statusClass(code: number): string {
    if (code >= 200 && code < 300) return 'con__net-status--2';
    if (code >= 300 && code < 400) return 'con__net-status--3';
    if (code >= 400 && code < 500) return 'con__net-status--4';
    if (code >= 500) return 'con__net-status--5';
    return 'con__net-status--0';
  }

  netTimeLabel(t: number): string {
    const d = new Date(t);
    const pad = (n: number, w = 2): string => String(n).padStart(w, '0');
    return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad(d.getMilliseconds(), 3)}`;
  }
}

import { Injectable } from '@angular/core';

export interface EncryptedBackupFileV1 {
  devLensEncryptedBackup: 1;
  salt: string;
  iv: string;
  data: string;
}

@Injectable({ providedIn: 'root' })
export class BackupCryptoService {
  async encryptJson(payload: unknown, passphrase: string): Promise<string> {
    const enc = new TextEncoder();
    const salt = crypto.getRandomValues(new Uint8Array(16));
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const keyMaterial = await crypto.subtle.importKey(
      'raw',
      enc.encode(passphrase),
      { name: 'PBKDF2' },
      false,
      ['deriveBits', 'deriveKey'],
    );
    const key = await crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt, iterations: 120_000, hash: 'SHA-256' },
      keyMaterial,
      { name: 'AES-GCM', length: 256 },
      false,
      ['encrypt'],
    );
    const pt = enc.encode(JSON.stringify(payload));
    const ct = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, pt);
    const blob: EncryptedBackupFileV1 = {
      devLensEncryptedBackup: 1,
      salt: btoa(String.fromCharCode(...salt)),
      iv: btoa(String.fromCharCode(...iv)),
      data: btoa(String.fromCharCode(...new Uint8Array(ct))),
    };
    return JSON.stringify(blob);
  }

  async decryptJson<T>(jsonText: string, passphrase: string): Promise<T> {
    const o = JSON.parse(jsonText) as EncryptedBackupFileV1;
    if (o.devLensEncryptedBackup !== 1 || !o.salt || !o.iv || !o.data) {
      throw new Error('Invalid backup file');
    }
    const enc = new TextEncoder();
    const dec = new TextDecoder();
    const salt = Uint8Array.from(atob(o.salt), (c) => c.charCodeAt(0));
    const iv = Uint8Array.from(atob(o.iv), (c) => c.charCodeAt(0));
    const data = Uint8Array.from(atob(o.data), (c) => c.charCodeAt(0));
    const keyMaterial = await crypto.subtle.importKey(
      'raw',
      enc.encode(passphrase),
      { name: 'PBKDF2' },
      false,
      ['deriveBits', 'deriveKey'],
    );
    const key = await crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt, iterations: 120_000, hash: 'SHA-256' },
      keyMaterial,
      { name: 'AES-GCM', length: 256 },
      false,
      ['decrypt'],
    );
    const pt = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, key, data);
    return JSON.parse(dec.decode(pt)) as T;
  }
}

import { Injectable, computed, inject, signal } from '@angular/core';
import { workspaceBrowserPartition } from '@dev-lens/shared';
import { TabsService } from './tabs.service';

export interface GuestConsoleLine {
  tabId: string;
  level: string;
  msg: string;
  t: number;
  source: 'guest' | 'repl';
}

export interface NetworkLogLine {
  partition: string;
  method: string;
  url: string;
  statusCode: number;
  t: number;
  /** Chromium resource type from `webRequest` (e.g. `xhr`, `script`, `mainFrame`). */
  resourceType: string;
}

const MAX_CONSOLE = 400;
const MAX_NET = 300;

@Injectable({ providedIn: 'root' })
export class GuestLogService {
  private readonly tabs = inject(TabsService);

  private readonly consoleLines = signal<GuestConsoleLine[]>([]);
  private readonly networkLines = signal<NetworkLogLine[]>([]);

  /** `all` or a Chromium `resourceType` value (`xhr`, `mainFrame`, …). */
  readonly networkResourceFilter = signal<string>('all');

  readonly activePartition = computed(() => {
    const t = this.tabs.activeTab();
    if (!t || t.kind !== 'browser') return null;
    return workspaceBrowserPartition(t.workspaceId);
  });

  readonly filteredConsole = computed(() => {
    const id = this.tabs.activeTabId();
    if (!id) return [];
    return this.consoleLines()
      .filter((l) => l.tabId === id)
      .sort((a, b) => a.t - b.t);
  });

  readonly filteredNetwork = computed(() => {
    const p = this.activePartition();
    if (!p) return [];
    const f = this.networkResourceFilter();
    let rows = this.networkLines().filter((l) => l.partition === p);
    if (f !== 'all') {
      rows = rows.filter((l) => (l.resourceType || 'other') === f);
    }
    return rows.sort((a, b) => b.t - a.t).slice(0, 150);
  });

  pushGuest(tabId: string, payload: { level?: string; msg?: string; t?: number }): void {
    const level = payload.level ?? 'log';
    const msg = payload.msg ?? '';
    const t = payload.t ?? Date.now();
    this.consoleLines.update((list) =>
      [{ tabId, level, msg, t, source: 'guest' as const }, ...list].slice(0, MAX_CONSOLE),
    );
  }

  pushRepl(tabId: string, level: 'info' | 'error' | 'result', text: string): void {
    const t = Date.now();
    this.consoleLines.update((list) =>
      [{ tabId, level, msg: text, t, source: 'repl' as const }, ...list].slice(0, MAX_CONSOLE),
    );
  }

  pushNetwork(line: NetworkLogLine): void {
    const normalized: NetworkLogLine = {
      ...line,
      resourceType: line.resourceType || 'other',
    };
    this.networkLines.update((list) => [normalized, ...list].slice(0, MAX_NET));
  }

  setNetworkResourceFilter(value: string): void {
    this.networkResourceFilter.set(value);
  }

  clearConsoleForActiveTab(): void {
    const id = this.tabs.activeTabId();
    if (!id) return;
    this.consoleLines.update((list) => list.filter((l) => l.tabId !== id));
  }

  clearNetworkForActivePartition(): void {
    const p = this.activePartition();
    if (!p) return;
    this.networkLines.update((list) => list.filter((l) => l.partition !== p));
  }

  clearTab(tabId: string): void {
    this.consoleLines.update((list) => list.filter((l) => l.tabId !== tabId));
  }

  exportHarForActivePartition(): string {
    const p = this.activePartition();
    const lines = p ? this.networkLines().filter((l) => l.partition === p) : [];
    const started =
      lines.length > 0
        ? new Date(Math.min(...lines.map((l) => l.t))).toISOString()
        : new Date().toISOString();
    const entries = lines.map((l) => ({
      startedDateTime: new Date(l.t).toISOString(),
      time: 0,
      comment: `resourceType:${l.resourceType || 'other'}`,
      request: { method: l.method, url: l.url, httpVersion: 'HTTP/1.1', headers: [] },
      response: { status: l.statusCode, statusText: '', httpVersion: 'HTTP/1.1', headers: [] },
    }));
    return JSON.stringify(
      {
        log: {
          version: '1.2',
          creator: { name: 'Dev-Lens' },
          pages: [],
          entries,
          startedDateTime: started,
        },
      },
      null,
      2,
    );
  }
}

import { Component, computed, inject } from '@angular/core';
import type { HistoryEntryDTO } from '@dev-lens/shared';
import { PersistedStateService } from '@core/services/persisted-state.service';
import { TabsService } from '@core/services/tabs.service';
import { ToastService } from '@core/services/toast.service';

interface HistoryDayGroup {
  label: string;
  entries: HistoryEntryDTO[];
}

@Component({
  selector: 'app-history-widget',
  imports: [],
  templateUrl: './history-widget.component.html',
  styleUrl: './history-widget.component.scss',
})
export class HistoryWidgetComponent {
  readonly persisted = inject(PersistedStateService);
  private readonly tabs = inject(TabsService);
  private readonly toast = inject(ToastService);

  readonly groups = computed((): HistoryDayGroup[] => {
    const h = this.persisted.snapshot()?.history ?? [];
    const sorted = [...h].sort((a, b) => b.at - a.at);
    const map = new Map<string, HistoryEntryDTO[]>();
    const today = new Date();
    const todayStr = today.toDateString();
    for (const e of sorted) {
      const d = new Date(e.at);
      let label: string;
      if (d.toDateString() === todayStr) label = 'Today';
      else if (d.toDateString() === new Date(today.getTime() - 86400000).toDateString())
        label = 'Yesterday';
      else
        label = d.toLocaleDateString(undefined, {
          weekday: 'short',
          month: 'short',
          day: 'numeric',
          year: 'numeric',
        });
      if (!map.has(label)) map.set(label, []);
      map.get(label)!.push(e);
    }
    return [...map.entries()].map(([label, entries]) => ({ label, entries }));
  });

  openUrl(url: string): void {
    void this.tabs.addBrowserTab(url, url);
  }

  formatTime(at: number): string {
    return new Date(at).toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
  }

  async removeEntry(id: string): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    await this.persisted.patch({ history: snap.history.filter((e) => e.id !== id) });
  }

  async clearAllHistory(): Promise<void> {
    await this.persisted.patch({ history: [] });
    this.toast.show('Browsing history cleared.');
  }
}

import { Component, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface ApiResponse {
  status: number;
  statusText: string;
  elapsed: number;
  body: string;
  headers: Record<string, string>;
}

interface HistoryItem {
  method: string;
  url: string;
  body: string;
  headersText: string;
  at: number;
}

const METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'HEAD'] as const;
type HttpMethod = (typeof METHODS)[number];

function parseHeaderLines(raw: string): Record<string, string> {
  const o: Record<string, string> = {};
  for (const line of raw.split('\n')) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const i = t.indexOf(':');
    if (i > 0) {
      const k = t.slice(0, i).trim();
      const v = t.slice(i + 1).trim();
      if (k) o[k] = v;
    }
  }
  return o;
}

@Component({
  selector: 'app-api-tester-widget',
  imports: [FormsModule],
  templateUrl: './api-tester-widget.component.html',
  styleUrl: './api-tester-widget.component.scss',
})
export class ApiTesterWidgetComponent {
  readonly methods = METHODS;
  readonly method = signal<HttpMethod>('GET');
  readonly url = signal('');
  readonly body = signal('');
  readonly requestHeadersText = signal('');
  readonly bearerToken = signal('');
  readonly basicUser = signal('');
  readonly basicPassword = signal('');
  readonly loading = signal(false);
  readonly response = signal<ApiResponse | null>(null);
  readonly error = signal('');
  readonly showBody = signal(false);
  readonly showReqHeaders = signal(false);
  readonly showRespHeaders = signal(true);
  readonly history = signal<HistoryItem[]>([]);

  get statusColor(): string {
    const s = this.response()?.status ?? 0;
    if (s >= 200 && s < 300) return 'success';
    if (s >= 300 && s < 400) return 'warn';
    return 'error';
  }

  formattedBody(): string {
    const raw = this.response()?.body ?? '';
    try {
      return JSON.stringify(JSON.parse(raw), null, 2);
    } catch {
      return raw;
    }
  }

  responseHeaderLines(): { key: string; value: string }[] {
    const h = this.response()?.headers ?? {};
    return Object.keys(h)
      .sort()
      .map((key) => ({ key, value: h[key] }));
  }

  responseHeadersFormatted(): string {
    return this.responseHeaderLines()
      .map((l) => `${l.key}: ${l.value}`)
      .join('\n');
  }

  historyUrlShort(u: string): string {
    return u.length > 36 ? u.slice(0, 36) + '…' : u;
  }

  applyBearer(): void {
    const t = this.bearerToken().trim();
    if (!t) return;
    const cur = this.requestHeadersText();
    const lines = cur.split('\n').filter((l) => !/^authorization\s*:/i.test(l.trim()));
    const next = [...lines, `Authorization: Bearer ${t}`].join('\n');
    this.requestHeadersText.set(next);
  }

  applyBasic(): void {
    const u = this.basicUser().trim();
    if (!u) return;
    const p = this.basicPassword();
    const token = typeof btoa === 'function' ? btoa(`${u}:${p}`) : '';
    if (!token) return;
    const cur = this.requestHeadersText();
    const lines = cur.split('\n').filter((l) => !/^authorization\s*:/i.test(l.trim()));
    const next = [...lines, `Authorization: Basic ${token}`].join('\n');
    this.requestHeadersText.set(next);
  }

  loadHistoryItem(h: HistoryItem): void {
    this.method.set(h.method as HttpMethod);
    this.url.set(h.url);
    this.body.set(h.body);
    this.requestHeadersText.set(h.headersText);
  }

  async send(): Promise<void> {
    const target = this.url().trim();
    if (!target) return;
    this.loading.set(true);
    this.response.set(null);
    this.error.set('');
    const start = Date.now();
    const m = this.method();
    const headerObj = parseHeaderLines(this.requestHeadersText());
    if (m !== 'GET' && m !== 'HEAD' && this.body().trim()) {
      if (!headerObj['Content-Type'] && !headerObj['content-type']) {
        headerObj['Content-Type'] = 'application/json';
      }
    }
    try {
      const init: RequestInit = {
        method: m,
        headers: headerObj,
      };
      if (m !== 'GET' && m !== 'HEAD' && this.body().trim()) {
        init.body = this.body();
      }
      const res = await fetch(target, init);
      const text = await res.text();
      const headers: Record<string, string> = {};
      res.headers.forEach((v, k) => {
        headers[k] = v;
      });
      this.response.set({
        status: res.status,
        statusText: res.statusText,
        elapsed: Date.now() - start,
        body: text,
        headers,
      });
      this.history.update((list) => {
        const item: HistoryItem = {
          method: m,
          url: target,
          body: this.body(),
          headersText: this.requestHeadersText(),
          at: Date.now(),
        };
        return [item, ...list.filter((x) => x.url !== target || x.method !== m)].slice(0, 20);
      });
    } catch (err) {
      this.error.set(err instanceof Error ? err.message : String(err));
    } finally {
      this.loading.set(false);
    }
  }
}

