interface ConsoleDisplayLine {
  level: DisplayLevel;
  text: string;
  time: string;
}

export interface DomNode {
  tag: string;
  id: string;
  classes: string;
  children: DomNode[];
  textSnippet: string;
}

export interface SourceEntry {
  name: string;
  type: string;
  size: number;
  duration: number;
}

export interface PerfMetrics {
  loadMs: number | null;
  domReadyMs: number | null;
  resources: number;
  scripts: number;
  memUsed: number | null;
  memTotal: number | null;
  paint: { name: string; time: number }[];
  lcp: number | null;
}

export const NETWORK_RESOURCE_FILTER_OPTIONS: { value: string; label: string }[] = [
  { value: 'all', label: 'All types' },
  { value: 'xhr', label: 'XHR' },
  { value: 'mainFrame', label: 'Document' },
  { value: 'subFrame', label: 'Subframe' },
  { value: 'script', label: 'Script' },
  { value: 'stylesheet', label: 'Stylesheet' },
  { value: 'image', label: 'Image' },
  { value: 'font', label: 'Font' },
  { value: 'media', label: 'Media' },
  { value: 'webSocket', label: 'WebSocket' },
  { value: 'ping', label: 'Ping' },
  { value: 'cspReport', label: 'CSP report' },
  { value: 'object', label: 'Object' },
  { value: 'other', label: 'Other' },
];

const DOM_SNAPSHOT_JS = `(function(){
  function snap(el, depth){
    if(!el||depth>4) return null;
    var cs=Array.from(el.children).slice(0,12).map(function(c){return snap(c,depth+1);}).filter(Boolean);
    var txt=el.children.length===0?(el.textContent||'').trim().slice(0,60):'';
    return {tag:(el.tagName||'').toLowerCase(),id:el.id||'',classes:(el.className&&typeof el.className==='string'?el.className.trim().split(/\\s+/).slice(0,3).join(' '):''),children:cs,textSnippet:txt};
  }
  return JSON.stringify(snap(document.body,0));
})()`;

const SOURCES_JS = `(function(){
  try{
    var entries=performance.getEntriesByType('resource');
    return JSON.stringify(entries.slice(0,80).map(function(e){
      return {name:e.name,type:e.initiatorType,size:Math.round(e.transferSize||0),duration:Math.round(e.duration)};
    }));
  }catch(ex){return '[]';}
})()`;

const PERF_JS = `(function(){
  var t=window.performance.timing||null;
  var entries=performance.getEntriesByType('resource');
  var paint=performance.getEntriesByType('paint').map(function(e){return {name:e.name,time:Math.round(e.startTime)};});
  var lcp=null;
  try{ if(typeof window.__devLensLcp==='number') lcp=Math.round(window.__devLensLcp); }catch(e){}
  return JSON.stringify({
    loadMs:t?(t.loadEventEnd-t.navigationStart)||null:null,
    domReadyMs:t?(t.domContentLoadedEventEnd-t.navigationStart)||null:null,
    resources:entries.length,
    scripts:entries.filter(function(e){return e.initiatorType==='script';}).length,
    memUsed:performance.memory?performance.memory.usedJSHeapSize:null,
    memTotal:performance.memory?performance.memory.totalJSHeapSize:null,
    paint:paint,lcp:lcp
  });
})()`;

function formatTime(t: number): string {
  return new Date(t).toLocaleTimeString('en-US', { hour12: false });
}

function guestToDisplayLevel(line: GuestConsoleLine): DisplayLevel {
  if (line.source === 'repl')
    return line.level === 'error' ? 'error' : line.level === 'result' ? 'result' : 'info';
  if (line.level === 'warn') return 'warn';
  if (line.level === 'error') return 'error';
  return 'info';
}

function fmtBytes(b: number | null): string {
  if (b === null) return '—';
  if (b < 1024) return `${b} B`;
  if (b < 1024 * 1024) return `${(b / 1024).toFixed(1)} KB`;
  return `${(b / 1024 / 1024).toFixed(1)} MB`;
}

type DtStatus = 'idle' | 'attaching' | 'attached' | 'no-tab' | 'error';

@Component({
  selector: 'app-console-widget',
  imports: [FormsModule, NgTemplateOutlet],
  templateUrl: './console-widget.component.html',
  styleUrl: './console-widget.component.scss',
})
export class ConsoleWidgetComponent {
  private readonly tabs = inject(TabsService);
  private readonly features = inject(FeatureFlagsService);
  readonly bridge = inject(ElectronBridgeService);
  private readonly destroyRef = inject(DestroyRef);
  readonly guestLog = inject(GuestLogService);
  private readonly resizeState = inject(ResizeStateService);

  /** Container div that marks where the BrowserView overlay should sit. */
  private readonly dtAreaRef = viewChild<ElementRef>('dtArea');

  /** Whether the currently active tab is a browser tab (has a guest webview). */
  readonly activeBrowserTabId = computed(() => {
    const tab = this.tabs.activeTab();
    return tab?.kind === 'browser' ? tab.id : null;
  });

  readonly dtStatus = signal<DtStatus>('idle');
  readonly dtError = signal<string | null>(null);

  /** WebContentsId of the guest we currently have DevTools attached to. */
  private lastGuestWcId: number | null = null;

  private resizeObserver: ResizeObserver | null = null;
  private intersectionObserver: IntersectionObserver | null = null;

  readonly activeTab = signal<PanelTab>('console');
  readonly command = signal('');

  readonly consoleLines = computed<ConsoleDisplayLine[]>(() =>
    this.guestLog.filteredConsole().map((l) => ({
      level: guestToDisplayLevel(l),
      text: l.msg,
      time: formatTime(l.t),
    })),
  );

  readonly networkLines = this.guestLog.filteredNetwork;
  readonly networkUrlFilter = signal('');
  readonly filteredNetworkLines = computed(() => {
    const q = this.networkUrlFilter().trim().toLowerCase();
    const rows = this.networkLines();
    return q ? rows.filter((r) => r.url.toLowerCase().includes(q)) : rows;
  });
  readonly netFilterOptions = NETWORK_RESOURCE_FILTER_OPTIONS;

  readonly domTree = signal<DomNode | null>(null);
  readonly domLoading = signal(false);
  readonly sourcesEntries = signal<SourceEntry[]>([]);
  readonly sourcesLoading = signal(false);
  readonly perfMetrics = signal<PerfMetrics | null>(null);
  readonly perfLoading = signal(false);

  readonly fmtBytes = fmtBytes;

  constructor() {
    if (this.bridge.isElectron) {
      this.setupElectronDevTools();
    }

    // Detach cleanly when the component is destroyed.
    this.destroyRef.onDestroy(() => {
      this.teardownObservers();
      void this.detachDevTools();
    });

    // Refresh custom panel data when switching tabs (non-Electron fallback).
    effect(() => {
      if (this.bridge.isElectron) return;
      const tab = this.activeTab();
      if (tab === 'elements') void this.refreshElements();
      else if (tab === 'sources') void this.refreshSources();
      else if (tab === 'performance') void this.refreshPerf();
    });
  }

  private setupElectronDevTools(): void {
    let prevBrowserTabId: string | null = null;

    // React to active-tab changes: detach the old DevTools and re-attach for the
    // new tab. The actual DEVTOOLS_ATTACH IPC is deferred until the #dtArea div
    // is in the DOM and has non-zero dimensions.
    effect(() => {
      const id = this.activeBrowserTabId();
      if (id === prevBrowserTabId) return;
      prevBrowserTabId = id;

      void this.detachDevTools();

      if (id === null) {
        this.dtStatus.set('no-tab');
      } else {
        this.dtStatus.set('attaching');
        this.dtError.set(null);
        // dtArea may not be in the DOM yet (first render); retry until visible.
        void this.attachWhenReady();
      }
    });

    // When #dtArea appears or disappears, wire up / tear down the observers that
    // keep the BrowserView overlay in sync with the element's position & size.
    effect(() => {
      const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
      if (el) {
        this.setupObservers(el);
      } else {
        this.teardownObservers();
      }
    });

    // Register synchronous hide/restore callbacks with ResizeStateService.
    // These fire IMMEDIATELY inside onResizeDown / onResizeUp in the
    // right-sidebar component — before any mousemove can reach the
    // BrowserView overlay and steal pointer events.
    this.resizeState.registerOverlayCallbacks(
      // hide — called synchronously on mousedown
      () => {
        if (this.lastGuestWcId !== null) this.hideOverlay();
      },
      // restore — called synchronously on mouseup; rAF lets the browser
      // finish painting the sidebar at its final width before we read bounds.
      () => {
        if (this.lastGuestWcId !== null) {
          requestAnimationFrame(() => {
            const bounds = this.getDtBounds();
            if (bounds) void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
          });
        }
      },
    );
  }

  // ── BrowserView overlay helpers ─────────────────────────────────────────────

  private getDtBounds(): { x: number; y: number; width: number; height: number } | null {
    const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
    if (!el) return null;
    const r = el.getBoundingClientRect();
    if (r.width < 4 || r.height < 4) return null;
    return {
      x: Math.round(r.left),
      y: Math.round(r.top),
      width: Math.round(r.width),
      height: Math.round(r.height),
    };
  }

  /** Try to attach DevTools, retrying with rAF if the area isn't rendered yet. */
  private async attachWhenReady(attempt = 0): Promise<void> {
    const bounds = this.getDtBounds();
    if (!bounds) {
      if (attempt < 60) {
        await new Promise<void>((res) => requestAnimationFrame(() => res()));
        return this.attachWhenReady(attempt + 1);
      }
      // After ~1s of retries still no bounds — leave status as 'attaching' so
      // the IntersectionObserver can recover when the panel becomes visible.
      return;
    }
    await this.attachDevTools(bounds);
  }

  private async attachDevTools(bounds: {
    x: number;
    y: number;
    width: number;
    height: number;
  }): Promise<void> {
    const guestWcId = this.tabs.getActiveGuestWcId();
    if (!guestWcId) {
      this.dtStatus.set('no-tab');
      return;
    }

    this.lastGuestWcId = guestWcId;

    const res = await this.bridge.invoke<{ ok: boolean; error?: string }>(
      RENDERER_INVOKE.DEVTOOLS_ATTACH,
      { guestWcId, bounds },
    );

    if (res.ok) {
      this.dtStatus.set('attached');
      this.dtError.set(null);
    } else {
      this.dtStatus.set('error');
      this.dtError.set(res.error ?? 'Failed to attach DevTools.');
      this.lastGuestWcId = null;
    }
  }

  private async detachDevTools(): Promise<void> {
    const wcId = this.lastGuestWcId;
    this.lastGuestWcId = null;
    if (wcId !== null) {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, { guestWcId: wcId });
    } else {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, {});
    }
  }

  /** Reposition the overlay to match the current #dtArea bounds. */
  private updateBounds(): void {
    if (this.lastGuestWcId === null) return;
    if (this.resizeState.isSidebarResizing()) return;
    const bounds = this.getDtBounds();
    if (bounds) {
      void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
    }
  }

  /** Move overlay off-screen without detaching the DevTools connection. */
  private hideOverlay(): void {
    void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, {
      bounds: { x: -32000, y: -32000, width: 1, height: 1 },
    });
  }

  private setupObservers(el: HTMLElement): void {
    this.teardownObservers();

    // Keep overlay in sync when the element resizes (e.g. sidebar width changes).
    this.resizeObserver = new ResizeObserver(() => this.updateBounds());
    this.resizeObserver.observe(el);

    // Hide/show the BrowserView overlay when the element scrolls out of view
    // (e.g. user collapses the right sidebar).
    this.intersectionObserver = new IntersectionObserver(
      (entries) => {
        const visible = entries.some((e) => e.isIntersecting);
        if (visible) {
          if (this.lastGuestWcId !== null) {
            this.updateBounds();
          } else if (this.activeBrowserTabId() !== null) {
            void this.attachWhenReady();
          }
        } else {
          this.hideOverlay();
        }
      },
      { threshold: 0.01 },
    );
    this.intersectionObserver.observe(el);

    // Also handle window-level resize (position may shift even if element size stays the same).
    const onWindowResize = (): void => this.updateBounds();
    window.addEventListener('resize', onWindowResize);
    this.destroyRef.onDestroy(() => window.removeEventListener('resize', onWindowResize));
  }

  private teardownObservers(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;
    this.intersectionObserver?.disconnect();
    this.intersectionObserver = null;
  }

  // ── Non-Electron fallback helpers ──────────────────────────────────────────

  async refreshElements(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.domLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(DOM_SNAPSHOT_JS);
      this.domTree.set(raw ? (JSON.parse(raw as string) as DomNode) : null);
    } catch {
      this.domTree.set(null);
    } finally {
      this.domLoading.set(false);
    }
  }

  async refreshSources(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.sourcesLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(SOURCES_JS);
      this.sourcesEntries.set(raw ? (JSON.parse(raw as string) as SourceEntry[]) : []);
    } catch {
      this.sourcesEntries.set([]);
    } finally {
      this.sourcesLoading.set(false);
    }
  }

  async refreshPerf(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.perfLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(PERF_JS);
      this.perfMetrics.set(raw ? (JSON.parse(raw as string) as PerfMetrics) : null);
    } catch {
      this.perfMetrics.set(null);
    } finally {
      this.perfLoading.set(false);
    }
  }

  async runCommand(): Promise<void> {
    const code = this.command().trim();
    const tabId = this.tabs.activeTabId();
    if (!code || !tabId) return;
    this.command.set('');
    this.guestLog.pushRepl(tabId, 'info', `> ${code}`);
    try {
      const result = await this.tabs.executeJavaScriptInActive(code);
      const text = result === undefined ? 'undefined' : JSON.stringify(result, null, 2);
      this.guestLog.pushRepl(tabId, 'result', text);
    } catch (err) {
      this.guestLog.pushRepl(tabId, 'error', err instanceof Error ? err.message : String(err));
    }
  }

  openNativeDevTools(): void {
    if (!this.features.mode('devtools')) return;
    void this.tabs.toggleDevtools();
  }

  clearPanel(): void {
    if (this.activeTab() === 'console') this.guestLog.clearConsoleForActiveTab();
    else if (this.activeTab() === 'network') this.guestLog.clearNetworkForActivePartition();
  }

  exportHar(): void {
    const json = this.guestLog.exportHarForActivePartition();
    const blob = new Blob([json], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-network-${Date.now()}.har`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  statusClass(code: number): string {
    if (code >= 200 && code < 300) return 'con__net-status--2';
    if (code >= 300 && code < 400) return 'con__net-status--3';
    if (code >= 400 && code < 500) return 'con__net-status--4';
    if (code >= 500) return 'con__net-status--5';
    return 'con__net-status--0';
  }

  netTimeLabel(t: number): string {
    const d = new Date(t);
    const pad = (n: number, w = 2): string => String(n).padStart(w, '0');
    return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad(d.getMilliseconds(), 3)}`;
  }
}

import {
  Component,
  ElementRef,
  HostListener,
  inject,
  signal,
  computed,
  effect,
  viewChild,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { FeatureFlagsService } from '@core/services/feature-flags.service';
import { LayoutService } from '@core/services/layout.service';
import { PersistedStateService } from '@core/services/persisted-state.service';
import { TabsService } from '@core/services/tabs.service';
import { NotesService } from '@core/services/notes.service';
import { WidgetRegistryService } from '@core/services/widget-registry.service';
import { SpotlightService } from './spotlight.service';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';

type CategoryKey = 'TABS' | 'BOOKMARKS' | 'HISTORY' | 'NOTES' | 'COMMANDS';

interface Row {
  id: string;
  label: string;
  sub?: string;
  category: CategoryKey;
  run: () => void;
}

@Component({
  selector: 'app-spotlight',
  imports: [FormsModule, TranslatePipe],
  templateUrl: './spotlight.component.html',
  styleUrl: './spotlight.component.scss',
})
export class SpotlightComponent {
  readonly spotlight = inject(SpotlightService);
  private readonly inputRef = viewChild<ElementRef<HTMLInputElement>>('spotIn');
  private readonly tabs = inject(TabsService);
  private readonly persisted = inject(PersistedStateService);
  private readonly notes = inject(NotesService);
  private readonly layout = inject(LayoutService);
  private readonly widgets = inject(WidgetRegistryService);
  private readonly features = inject(FeatureFlagsService);

  readonly query = signal('');
  readonly selected = signal(0);

  constructor() {
    effect(() => {
      if (this.spotlight.open()) {
        queueMicrotask(() => this.inputRef()?.nativeElement?.focus());
      }
    });
  }

  readonly rows = computed(() => {
    const ff = this.features.flags();
    const q = this.query().trim().toLowerCase();
    const rows: Row[] = [];

    for (const t of this.tabs.tabs()) {
      const hay = `${t.title} ${t.url}`.toLowerCase();
      if (!q || hay.includes(q)) {
        rows.push({
          id: `tab-${t.id}`,
          label: t.title || 'Tab',
          sub: t.url,
          category: 'TABS',
          run: () => {
            void this.tabs.selectTab(t.id);
            this.spotlight.hide();
          },
        });
      }
    }

    for (const b of this.persisted.snapshot()?.bookmarks ?? []) {
      const hay = `${b.title} ${b.url}`.toLowerCase();
      if (!q || hay.includes(q)) {
        rows.push({
          id: `bm-${b.id}`,
          label: b.title,
          sub: b.url,
          category: 'BOOKMARKS',
          run: () => {
            void this.tabs.addBrowserTab(b.url, b.title);
            this.spotlight.hide();
          },
        });
      }
    }

    for (const h of (this.persisted.snapshot()?.history ?? []).slice(0, 40)) {
      const hay = `${h.title} ${h.url}`.toLowerCase();
      if (!q || hay.includes(q)) {
        rows.push({
          id: `hist-${h.id}`,
          label: h.title,
          sub: h.url,
          category: 'HISTORY',
          run: () => {
            void this.tabs.addBrowserTab(h.url, h.title);
            this.spotlight.hide();
          },
        });
      }
    }

    for (const n of this.notes.notes()) {
      const hay = `${n.title} ${n.body}`.toLowerCase();
      if (!q || hay.includes(q)) {
        rows.push({
          id: `note-${n.id}`,
          label: n.title || 'Note',
          sub: n.body.slice(0, 80),
          category: 'NOTES',
          run: () => {
            this.spotlight.hide();
            if (!ff.rightSidebar || !ff.widgets.notes) return;
            this.layout.openRightSidebar();
            this.widgets.select('notes');
            this.notes.requestFocusNote(n.id);
          },
        });
      }
    }

    rows.push(
      {
        id: 'cmd-new-tab',
        label: 'New browser tab',
        category: 'COMMANDS',
        run: () => {
          void this.tabs.addBrowserTab('about:blank', 'New Tab');
          this.spotlight.hide();
        },
      },
      {
        id: 'cmd-settings',
        label: 'Open settings',
        category: 'COMMANDS',
        run: () => {
          void this.tabs.addInternalTab('settings', 'Settings');
          this.spotlight.hide();
        },
      },
    );

    return rows;
  });

  readonly visible = this.spotlight.open;

  onInput(): void {
    this.selected.set(0);
  }

  pick(i: number): void {
    const r = this.rows()[i];
    if (r) r.run();
  }

  @HostListener('document:keydown', ['$event'])
  onDocKey(ev: KeyboardEvent): void {
    if (!this.spotlight.open()) return;
    if (ev.key === 'Escape') {
      ev.preventDefault();
      this.spotlight.hide();
      return;
    }
    if (ev.key === 'ArrowDown') {
      ev.preventDefault();
      const n = this.rows().length;
      if (n) this.selected.update((i) => (i + 1) % n);
    }
    if (ev.key === 'ArrowUp') {
      ev.preventDefault();
      const n = this.rows().length;
      if (n) this.selected.update((i) => (i - 1 + n) % n);
    }
    if (ev.key === 'Enter') {
      ev.preventDefault();
      this.pick(this.selected());
    }
  }
}

import { Injectable, computed, effect, inject, signal } from '@angular/core';
import type { DevLensFeatureWidgetFlags } from '@dev-lens/shared';
import { FeatureFlagsService } from './feature-flags.service';
import { PluginRuntimeService } from './plugin-runtime.service';

export interface SidebarWidgetDescriptor {
  id: string;
  title: string;
  order: number;
}

export const WIDGET_IDS = [
  'bookmarks',
  'notes',
  'ai',
  'console',
  'clipboard',
  'sessions',
  'api',
  'history',
  'readlater',
  'perf',
  'json',
] as const;
export type WidgetId = (typeof WIDGET_IDS)[number];

const WIDGET_FLAG: Record<string, keyof DevLensFeatureWidgetFlags> = {
  bookmarks: 'bookmarks',
  notes: 'notes',
  ai: 'ai',
  console: 'console',
  clipboard: 'clipboard',
  sessions: 'sessions',
  api: 'api',
  history: 'history',
  readlater: 'readlater',
  perf: 'perf',
  json: 'json',
};

@Injectable({ providedIn: 'root' })
export class WidgetRegistryService {
  private readonly plugins = inject(PluginRuntimeService);
  private readonly features = inject(FeatureFlagsService);

  private readonly _builtins: SidebarWidgetDescriptor[] = [
    { id: 'bookmarks', title: 'Bookmarks', order: -1 },
    { id: 'notes', title: 'Notes', order: 0 },
    { id: 'ai', title: 'AI Assistant', order: 1 },
    { id: 'console', title: 'Console', order: 2 },
    { id: 'clipboard', title: 'Clipboard', order: 3 },
    { id: 'sessions', title: 'Sessions', order: 4 },
    { id: 'api', title: 'API Tester', order: 5 },
    { id: 'history', title: 'History', order: 6 },
    { id: 'readlater', title: 'Read later', order: 7 },
    { id: 'perf', title: 'Performance', order: 8 },
    { id: 'json', title: 'JSON', order: 9 },
  ];

  /** Built-in + plugin widgets visible with current feature flags (empty if right sidebar off). */
  readonly widgets = computed(() => {
    const ff = this.features.flags();
    if (!ff.rightSidebar) return [];
    const extra = this.plugins.sidebarPlugins().map((p, i) => ({
      id: `plugin:${p.id}`,
      title: p.sidebarTitle,
      order: 100 + i,
    }));
    const combined = [...this._builtins, ...extra].sort((a, b) => a.order - b.order);
    return combined.filter((w) => {
      if (w.id.startsWith('plugin:')) return true;
      const key = WIDGET_FLAG[w.id];
      return key ? ff.widgets[key] : true;
    });
  });

  readonly activeId = signal<string>('notes');

  constructor() {
    effect(() => {
      const list = this.widgets();
      if (list.length === 0) {
        this.activeId.set('');
        return;
      }
      const cur = this.activeId();
      if (cur && list.some((w) => w.id === cur)) return;
      this.activeId.set(list[0]!.id);
    });
  }

  select(id: string): void {
    if (!this.widgets().some((w) => w.id === id)) return;
    this.activeId.set(id);
  }
}

import {
  Component,
  DestroyRef,
  ElementRef,
  computed,
  effect,
  inject,
  signal,
  viewChild,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { NgTemplateOutlet } from '@angular/common';
import { GuestLogService, type GuestConsoleLine } from '@core/services/guest-log.service';
import { ResizeStateService } from '@core/services/resize-state.service';
import { FeatureFlagsService } from '@core/services/feature-flags.service';
import { TabsService } from '@core/services/tabs.service';
import { ElectronBridgeService } from '@core/services/electron-bridge.service';
import { RENDERER_INVOKE } from '@core/electron-ipc-channels';

type DisplayLevel = 'info' | 'warn' | 'error' | 'result';
type PanelTab = 'console' | 'network' | 'elements' | 'sources' | 'performance';

interface ConsoleDisplayLine {
  level: DisplayLevel;
  text: string;
  time: string;
}

export interface DomNode {
  tag: string;
  id: string;
  classes: string;
  children: DomNode[];
  textSnippet: string;
}

export interface SourceEntry {
  name: string;
  type: string;
  size: number;
  duration: number;
}

export interface PerfMetrics {
  loadMs: number | null;
  domReadyMs: number | null;
  resources: number;
  scripts: number;
  memUsed: number | null;
  memTotal: number | null;
  paint: { name: string; time: number }[];
  lcp: number | null;
}

export const NETWORK_RESOURCE_FILTER_OPTIONS: { value: string; label: string }[] = [
  { value: 'all', label: 'All types' },
  { value: 'xhr', label: 'XHR' },
  { value: 'mainFrame', label: 'Document' },
  { value: 'subFrame', label: 'Subframe' },
  { value: 'script', label: 'Script' },
  { value: 'stylesheet', label: 'Stylesheet' },
  { value: 'image', label: 'Image' },
  { value: 'font', label: 'Font' },
  { value: 'media', label: 'Media' },
  { value: 'webSocket', label: 'WebSocket' },
  { value: 'ping', label: 'Ping' },
  { value: 'cspReport', label: 'CSP report' },
  { value: 'object', label: 'Object' },
  { value: 'other', label: 'Other' },
];

const DOM_SNAPSHOT_JS = `(function(){
  function snap(el, depth){
    if(!el||depth>4) return null;
    var cs=Array.from(el.children).slice(0,12).map(function(c){return snap(c,depth+1);}).filter(Boolean);
    var txt=el.children.length===0?(el.textContent||'').trim().slice(0,60):'';
    return {tag:(el.tagName||'').toLowerCase(),id:el.id||'',classes:(el.className&&typeof el.className==='string'?el.className.trim().split(/\\s+/).slice(0,3).join(' '):''),children:cs,textSnippet:txt};
  }
  return JSON.stringify(snap(document.body,0));
})()`;

const SOURCES_JS = `(function(){
  try{
    var entries=performance.getEntriesByType('resource');
    return JSON.stringify(entries.slice(0,80).map(function(e){
      return {name:e.name,type:e.initiatorType,size:Math.round(e.transferSize||0),duration:Math.round(e.duration)};
    }));
  }catch(ex){return '[]';}
})()`;

const PERF_JS = `(function(){
  var t=window.performance.timing||null;
  var entries=performance.getEntriesByType('resource');
  var paint=performance.getEntriesByType('paint').map(function(e){return {name:e.name,time:Math.round(e.startTime)};});
  var lcp=null;
  try{ if(typeof window.__devLensLcp==='number') lcp=Math.round(window.__devLensLcp); }catch(e){}
  return JSON.stringify({
    loadMs:t?(t.loadEventEnd-t.navigationStart)||null:null,
    domReadyMs:t?(t.domContentLoadedEventEnd-t.navigationStart)||null:null,
    resources:entries.length,
    scripts:entries.filter(function(e){return e.initiatorType==='script';}).length,
    memUsed:performance.memory?performance.memory.usedJSHeapSize:null,
    memTotal:performance.memory?performance.memory.totalJSHeapSize:null,
    paint:paint,lcp:lcp
  });
})()`;

function formatTime(t: number): string {
  return new Date(t).toLocaleTimeString('en-US', { hour12: false });
}

function guestToDisplayLevel(line: GuestConsoleLine): DisplayLevel {
  if (line.source === 'repl')
    return line.level === 'error' ? 'error' : line.level === 'result' ? 'result' : 'info';
  if (line.level === 'warn') return 'warn';
  if (line.level === 'error') return 'error';
  return 'info';
}

function fmtBytes(b: number | null): string {
  if (b === null) return '—';
  if (b < 1024) return `${b} B`;
  if (b < 1024 * 1024) return `${(b / 1024).toFixed(1)} KB`;
  return `${(b / 1024 / 1024).toFixed(1)} MB`;
}

type DtStatus = 'idle' | 'attaching' | 'attached' | 'no-tab' | 'error';

@Component({
  selector: 'app-console-widget',
  imports: [FormsModule, NgTemplateOutlet],
  templateUrl: './console-widget.component.html',
  styleUrl: './console-widget.component.scss',
})
export class ConsoleWidgetComponent {
  private readonly tabs = inject(TabsService);
  private readonly features = inject(FeatureFlagsService);
  readonly bridge = inject(ElectronBridgeService);
  private readonly destroyRef = inject(DestroyRef);
  readonly guestLog = inject(GuestLogService);
  private readonly resizeState = inject(ResizeStateService);

  /** Container div that marks where the BrowserView overlay should sit. */
  private readonly dtAreaRef = viewChild<ElementRef>('dtArea');

  /** Whether the currently active tab is a browser tab (has a guest webview). */
  readonly activeBrowserTabId = computed(() => {
    const tab = this.tabs.activeTab();
    return tab?.kind === 'browser' ? tab.id : null;
  });

  readonly dtStatus = signal<DtStatus>('idle');
  readonly dtError = signal<string | null>(null);

  /** WebContentsId of the guest we currently have DevTools attached to. */
  private lastGuestWcId: number | null = null;

  private resizeObserver: ResizeObserver | null = null;
  private intersectionObserver: IntersectionObserver | null = null;

  readonly activeTab = signal<PanelTab>('console');
  readonly command = signal('');

  readonly consoleLines = computed<ConsoleDisplayLine[]>(() =>
    this.guestLog.filteredConsole().map((l) => ({
      level: guestToDisplayLevel(l),
      text: l.msg,
      time: formatTime(l.t),
    })),
  );

  readonly networkLines = this.guestLog.filteredNetwork;
  readonly networkUrlFilter = signal('');
  readonly filteredNetworkLines = computed(() => {
    const q = this.networkUrlFilter().trim().toLowerCase();
    const rows = this.networkLines();
    return q ? rows.filter((r) => r.url.toLowerCase().includes(q)) : rows;
  });
  readonly netFilterOptions = NETWORK_RESOURCE_FILTER_OPTIONS;

  readonly domTree = signal<DomNode | null>(null);
  readonly domLoading = signal(false);
  readonly sourcesEntries = signal<SourceEntry[]>([]);
  readonly sourcesLoading = signal(false);
  readonly perfMetrics = signal<PerfMetrics | null>(null);
  readonly perfLoading = signal(false);

  readonly fmtBytes = fmtBytes;

  constructor() {
    if (this.bridge.isElectron) {
      this.setupElectronDevTools();
    }

    // Detach cleanly when the component is destroyed.
    this.destroyRef.onDestroy(() => {
      this.teardownObservers();
      void this.detachDevTools();
    });

    // Refresh custom panel data when switching tabs (non-Electron fallback).
    effect(() => {
      if (this.bridge.isElectron) return;
      const tab = this.activeTab();
      if (tab === 'elements') void this.refreshElements();
      else if (tab === 'sources') void this.refreshSources();
      else if (tab === 'performance') void this.refreshPerf();
    });
  }

  private setupElectronDevTools(): void {
    let prevBrowserTabId: string | null = null;

    // React to active-tab changes: detach the old DevTools and re-attach for the
    // new tab. The actual DEVTOOLS_ATTACH IPC is deferred until the #dtArea div
    // is in the DOM and has non-zero dimensions.
    effect(() => {
      const id = this.activeBrowserTabId();
      if (id === prevBrowserTabId) return;
      prevBrowserTabId = id;

      void this.detachDevTools();

      if (id === null) {
        this.dtStatus.set('no-tab');
      } else {
        this.dtStatus.set('attaching');
        this.dtError.set(null);
        // dtArea may not be in the DOM yet (first render); retry until visible.
        void this.attachWhenReady();
      }
    });

    // When #dtArea appears or disappears, wire up / tear down the observers that
    // keep the BrowserView overlay in sync with the element's position & size.
    effect(() => {
      const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
      if (el) {
        this.setupObservers(el);
      } else {
        this.teardownObservers();
      }
    });

    // Register synchronous hide/restore callbacks with ResizeStateService.
    // These fire IMMEDIATELY inside onResizeDown / onResizeUp in the
    // right-sidebar component — before any mousemove can reach the
    // BrowserView overlay and steal pointer events.
    this.resizeState.registerOverlayCallbacks(
      // hide — called synchronously on mousedown
      () => {
        if (this.lastGuestWcId !== null) this.hideOverlay();
      },
      // restore — called synchronously on mouseup; rAF lets the browser
      // finish painting the sidebar at its final width before we read bounds.
      () => {
        if (this.lastGuestWcId !== null) {
          requestAnimationFrame(() => {
            const bounds = this.getDtBounds();
            if (bounds) void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
          });
        }
      },
    );
  }

  // ── BrowserView overlay helpers ─────────────────────────────────────────────

  private getDtBounds(): { x: number; y: number; width: number; height: number } | null {
    const el = this.dtAreaRef()?.nativeElement as HTMLElement | undefined;
    if (!el) return null;
    const r = el.getBoundingClientRect();
    if (r.width < 4 || r.height < 4) return null;
    return {
      x: Math.round(r.left),
      y: Math.round(r.top),
      width: Math.round(r.width),
      height: Math.round(r.height),
    };
  }

  /** Try to attach DevTools, retrying with rAF if the area isn't rendered yet. */
  private async attachWhenReady(attempt = 0): Promise<void> {
    const bounds = this.getDtBounds();
    if (!bounds) {
      if (attempt < 60) {
        await new Promise<void>((res) => requestAnimationFrame(() => res()));
        return this.attachWhenReady(attempt + 1);
      }
      // After ~1s of retries still no bounds — leave status as 'attaching' so
      // the IntersectionObserver can recover when the panel becomes visible.
      return;
    }
    await this.attachDevTools(bounds);
  }

  private async attachDevTools(bounds: {
    x: number;
    y: number;
    width: number;
    height: number;
  }): Promise<void> {
    const guestWcId = this.tabs.getActiveGuestWcId();
    if (!guestWcId) {
      this.dtStatus.set('no-tab');
      return;
    }

    this.lastGuestWcId = guestWcId;

    const res = await this.bridge.invoke<{ ok: boolean; error?: string }>(
      RENDERER_INVOKE.DEVTOOLS_ATTACH,
      { guestWcId, bounds },
    );

    if (res.ok) {
      this.dtStatus.set('attached');
      this.dtError.set(null);
    } else {
      this.dtStatus.set('error');
      this.dtError.set(res.error ?? 'Failed to attach DevTools.');
      this.lastGuestWcId = null;
    }
  }

  private async detachDevTools(): Promise<void> {
    const wcId = this.lastGuestWcId;
    this.lastGuestWcId = null;
    if (wcId !== null) {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, { guestWcId: wcId });
    } else {
      await this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_DETACH, {});
    }
  }

  /** Reposition the overlay to match the current #dtArea bounds. */
  private updateBounds(): void {
    if (this.lastGuestWcId === null) return;
    if (this.resizeState.isSidebarResizing()) return;
    const bounds = this.getDtBounds();
    if (bounds) {
      void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, { bounds });
    }
  }

  /** Move overlay off-screen without detaching the DevTools connection. */
  private hideOverlay(): void {
    void this.bridge.invoke(RENDERER_INVOKE.DEVTOOLS_SET_BOUNDS, {
      bounds: { x: -32000, y: -32000, width: 1, height: 1 },
    });
  }

  private setupObservers(el: HTMLElement): void {
    this.teardownObservers();

    // Keep overlay in sync when the element resizes (e.g. sidebar width changes).
    this.resizeObserver = new ResizeObserver(() => this.updateBounds());
    this.resizeObserver.observe(el);

    // Hide/show the BrowserView overlay when the element scrolls out of view
    // (e.g. user collapses the right sidebar).
    this.intersectionObserver = new IntersectionObserver(
      (entries) => {
        const visible = entries.some((e) => e.isIntersecting);
        if (visible) {
          if (this.lastGuestWcId !== null) {
            this.updateBounds();
          } else if (this.activeBrowserTabId() !== null) {
            void this.attachWhenReady();
          }
        } else {
          this.hideOverlay();
        }
      },
      { threshold: 0.01 },
    );
    this.intersectionObserver.observe(el);

    // Also handle window-level resize (position may shift even if element size stays the same).
    const onWindowResize = (): void => this.updateBounds();
    window.addEventListener('resize', onWindowResize);
    this.destroyRef.onDestroy(() => window.removeEventListener('resize', onWindowResize));
  }

  private teardownObservers(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;
    this.intersectionObserver?.disconnect();
    this.intersectionObserver = null;
  }

  // ── Non-Electron fallback helpers ──────────────────────────────────────────

  async refreshElements(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.domLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(DOM_SNAPSHOT_JS);
      this.domTree.set(raw ? (JSON.parse(raw as string) as DomNode) : null);
    } catch {
      this.domTree.set(null);
    } finally {
      this.domLoading.set(false);
    }
  }

  async refreshSources(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.sourcesLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(SOURCES_JS);
      this.sourcesEntries.set(raw ? (JSON.parse(raw as string) as SourceEntry[]) : []);
    } catch {
      this.sourcesEntries.set([]);
    } finally {
      this.sourcesLoading.set(false);
    }
  }

  async refreshPerf(): Promise<void> {
    if (!this.tabs.activeTabId()) return;
    this.perfLoading.set(true);
    try {
      const raw = await this.tabs.executeJavaScriptInActive(PERF_JS);
      this.perfMetrics.set(raw ? (JSON.parse(raw as string) as PerfMetrics) : null);
    } catch {
      this.perfMetrics.set(null);
    } finally {
      this.perfLoading.set(false);
    }
  }

  async runCommand(): Promise<void> {
    const code = this.command().trim();
    const tabId = this.tabs.activeTabId();
    if (!code || !tabId) return;
    this.command.set('');
    this.guestLog.pushRepl(tabId, 'info', `> ${code}`);
    try {
      const result = await this.tabs.executeJavaScriptInActive(code);
      const text = result === undefined ? 'undefined' : JSON.stringify(result, null, 2);
      this.guestLog.pushRepl(tabId, 'result', text);
    } catch (err) {
      this.guestLog.pushRepl(tabId, 'error', err instanceof Error ? err.message : String(err));
    }
  }

  openNativeDevTools(): void {
    if (!this.features.mode('devtools')) return;
    void this.tabs.toggleDevtools();
  }

  clearPanel(): void {
    if (this.activeTab() === 'console') this.guestLog.clearConsoleForActiveTab();
    else if (this.activeTab() === 'network') this.guestLog.clearNetworkForActivePartition();
  }

  exportHar(): void {
    const json = this.guestLog.exportHarForActivePartition();
    const blob = new Blob([json], { type: 'application/json' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `dev-lens-network-${Date.now()}.har`;
    a.click();
    URL.revokeObjectURL(a.href);
  }

  statusClass(code: number): string {
    if (code >= 200 && code < 300) return 'con__net-status--2';
    if (code >= 300 && code < 400) return 'con__net-status--3';
    if (code >= 400 && code < 500) return 'con__net-status--4';
    if (code >= 500) return 'con__net-status--5';
    return 'con__net-status--0';
  }

  netTimeLabel(t: number): string {
    const d = new Date(t);
    const pad = (n: number, w = 2): string => String(n).padStart(w, '0');
    return `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}.${pad(d.getMilliseconds(), 3)}`;
  }
}

import { Injectable, signal } from '@angular/core';

export type ToastVariant = 'info' | 'error';

export interface ToastItem {
  id: string;
  text: string;
  variant: ToastVariant;
}

@Injectable({ providedIn: 'root' })
export class ToastService {
  private seq = 0;
  readonly items = signal<ToastItem[]>([]);

  show(text: string, variant: ToastVariant = 'info', durationMs = 4000): void {
    const id = `t-${++this.seq}`;
    this.items.update((a) => [...a, { id, text, variant }]);
    window.setTimeout(() => this.dismiss(id), durationMs);
  }

  error(text: string, durationMs = 5500): void {
    this.show(text, 'error', durationMs);
  }

  dismiss(id: string): void {
    this.items.update((a) => a.filter((x) => x.id !== id));
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { IPC_CHANNELS, IPC_EVENTS, type PersistedTabDTO } from '@dev-lens/shared';
import { ElectronBridgeService } from './electron-bridge.service';
import { InspectPointerService } from './inspect-pointer.service';
import { PersistedStateService } from './persisted-state.service';
import { SplitViewService } from './split-view.service';
import { WorkspaceService } from './workspace.service';

export interface UiTab {
  id: string;
  workspaceId: string;
  kind: 'browser' | 'internal';
  url: string;
  title: string;
  internalRoute?: string;
  pinned?: boolean;
  groupId?: string | null;
}

export interface WebviewHandler {
  navigate(url: string): void;
  back(): void;
  forward(): void;
  reload(): void;
  stop?: () => void;
  toggleDevtools(): void;
  executeJavaScript(code: string): Promise<unknown>;
  /** Unload guest to about:blank to reduce memory when tab is auto-suspended. */
  suspendToBlank(): void;
  /** DevTools “pick element” at guest viewport coordinates. */
  inspectElement?(x: number, y: number): void;
  /** Returns the Electron WebContentsId of the guest webview for DevTools attachment. */
  getWebContentsId?(): number | undefined;
}

function toUi(dto: PersistedTabDTO): UiTab {
  return {
    id: dto.id,
    workspaceId: dto.workspaceId,
    kind: dto.kind,
    url: dto.url,
    title: dto.title,
    internalRoute: dto.internalRoute,
    pinned: dto.pinned,
    groupId: dto.groupId ?? null,
  };
}

function toDto(t: UiTab): PersistedTabDTO {
  return {
    id: t.id,
    workspaceId: t.workspaceId,
    kind: t.kind,
    url: t.url,
    title: t.title,
    internalRoute: t.internalRoute,
    pinned: t.pinned,
    groupId: t.groupId,
  };
}

@Injectable({ providedIn: 'root' })
export class TabsService {
  private readonly bridge = inject(ElectronBridgeService);
  private readonly persisted = inject(PersistedStateService);
  private readonly workspace = inject(WorkspaceService);
  private readonly splitView = inject(SplitViewService);
  private readonly router = inject(Router);

  private readonly tabLastSelectedAt = new Map<string, number>();
  private readonly suspendedBrowserIds = new Set<string>();
  private suspendTimer: ReturnType<typeof setInterval> | null = null;

  readonly tabs = signal<UiTab[]>([]);
  readonly activeTabId = signal<string | null>(null);

  readonly visibleTabs = computed(() =>
    this.tabs().filter((t) => t.workspaceId === this.workspace.activeWorkspaceId()),
  );

  readonly activeTab = computed(() => {
    const id = this.activeTabId();
    if (!id) return undefined;
    return this.tabs().find((t) => t.id === id);
  });

  /** Browser tabs visible to Angular `@for` → `BrowserTabViewComponent`. */
  readonly browserTabs = computed(() => this.tabs().filter((t) => t.kind === 'browser'));

  // ── Webview handler registry ───────────────────────────────────────────────
  private readonly webviewHandlers = new Map<string, WebviewHandler>();
  private readonly inspectPointer = inject(InspectPointerService);

  /** Per-tab guest navigation state (updated from BrowserTabViewComponent). */
  private readonly guestNavState = signal<
    Record<string, { canBack: boolean; canFwd: boolean; loading: boolean }>
  >({});

  readonly activeGuestNav = computed(() => {
    const id = this.activeTabId();
    if (!id) return { canBack: false, canFwd: false, loading: false };
    return this.guestNavState()[id] ?? { canBack: false, canFwd: false, loading: false };
  });

  setGuestNavState(
    tabId: string,
    patch: Partial<{ canBack: boolean; canFwd: boolean; loading: boolean }>,
  ): void {
    this.guestNavState.update((m) => {
      const cur = m[tabId] ?? { canBack: false, canFwd: false, loading: false };
      return { ...m, [tabId]: { ...cur, ...patch } };
    });
  }

  registerWebview(tabId: string, handler: WebviewHandler): void {
    this.webviewHandlers.set(tabId, handler);
  }

  unregisterWebview(tabId: string): void {
    this.webviewHandlers.delete(tabId);
    this.guestNavState.update((m) => {
      const rest = { ...m };
      delete rest[tabId];
      return rest;
    });
  }

  private getActiveHandler(): WebviewHandler | undefined {
    const id = this.activeTabId();
    return id ? this.webviewHandlers.get(id) : undefined;
  }

  private applyHttpsOnly(url: string): string {
    if (!this.persisted.snapshot()?.settings.httpsOnlyMode) return url;
    const t = url.trim();
    if (t.toLowerCase().startsWith('http://')) return `https://${t.slice(7)}`;
    return url;
  }

  private reportActiveTabToMain(): void {
    if (!this.bridge.isElectron) return;
    const t = this.activeTab();
    if (!t || t.kind !== 'browser') {
      void this.bridge.invoke(IPC_CHANNELS.TABS_REPORT_ACTIVE, { url: '', title: '' });
      return;
    }
    void this.bridge.invoke(IPC_CHANNELS.TABS_REPORT_ACTIVE, { url: t.url, title: t.title });
  }

  // ── Reactive state update from BrowserTabViewComponent ────────────────────
  updateTabState(tabId: string, url: string, title: string): void {
    this.tabs.update((list) =>
      list.map((t) =>
        t.id === tabId && t.kind === 'browser'
          ? { ...t, url: url || t.url, title: title || url || t.title }
          : t,
      ),
    );
    if (tabId === this.activeTabId()) this.reportActiveTabToMain();
  }

  // ── Lifecycle ──────────────────────────────────────────────────────────────
  private listenersBound = false;

  bindMainProcessEvents(): void {
    if (this.listenersBound || !this.bridge.isElectron) return;
    this.listenersBound = true;
    this.bridge.on(IPC_EVENTS.PLUGIN_OPEN_URL, (raw) => {
      const p = raw as { url?: string; title?: string };
      if (!p.url?.trim()) return;
      void this.addBrowserTab(p.url, p.title || p.url);
    });
    // Blocker stats arrive via IPC_EVENTS.BLOCKER_STATS – handled in TopBarComponent.
    // Tab updates now come directly from BrowserTabViewComponent (no main-process round-trip).
    void this.bridge.invoke(IPC_CHANNELS.BLOCKER_GET_STATS);
    if (!this.suspendTimer) {
      this.suspendTimer = setInterval(() => this.applyAutoSuspend(), 30_000);
    }
  }

  isBrowserTabSuspended(tabId: string): boolean {
    return this.suspendedBrowserIds.has(tabId);
  }

  private applyAutoSuspend(): void {
    const mins = this.persisted.snapshot()?.settings.tabSuspendAfterMinutes ?? 0;
    if (!mins) {
      this.suspendedBrowserIds.clear();
      return;
    }
    const ms = mins * 60 * 1000;
    const now = Date.now();
    const active = this.activeTabId();
    const sec = this.splitView.enabled() ? this.splitView.secondaryTabId() : null;
    const ws = this.workspace.activeWorkspaceId();
    for (const t of this.tabs()) {
      if (t.workspaceId !== ws || t.kind !== 'browser') continue;
      if (t.id === active || t.id === sec) continue;
      const last = this.tabLastSelectedAt.get(t.id) ?? 0;
      if (now - last < ms) continue;
      if (this.suspendedBrowserIds.has(t.id)) continue;
      this.suspendedBrowserIds.add(t.id);
      this.webviewHandlers.get(t.id)?.suspendToBlank();
    }
  }

  async bootstrap(): Promise<void> {
    if (!this.bridge.isElectron) return;
    await this.persisted.hydrate();
    const snap = this.persisted.snapshot();
    if (!snap) return;

    if (snap.openTabs.length > 0) {
      // Restore tab state — BrowserTabViewComponents handle their own URL loading.
      this.tabs.set(snap.openTabs.map(toUi));
      const now = Date.now();
      for (const t of snap.openTabs) this.tabLastSelectedAt.set(t.id, now);
      const inWs = snap.openTabs.filter((t) => t.workspaceId === snap.activeWorkspaceId);
      const pick = inWs[0] ?? snap.openTabs[0];
      if (pick) await this.selectTab(pick.id, false);
    } else {
      await this.addInternalTab('new-tab', 'New Tab', false);
    }
  }

  async persistOpenTabs(): Promise<void> {
    await this.persisted.patch({ openTabs: this.tabs().map(toDto) });
  }

  async selectTab(tabId: string, persist = true): Promise<void> {
    this.activeTabId.set(tabId);
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;

    this.tabLastSelectedAt.set(tabId, Date.now());
    if (tab.kind === 'browser' && this.suspendedBrowserIds.has(tabId)) {
      this.suspendedBrowserIds.delete(tabId);
      this.webviewHandlers.get(tabId)?.navigate(tab.url);
    }

    if (tab.kind === 'internal') {
      const route = tab.internalRoute ?? 'new-tab';
      await this.router.navigateByUrl(`/${route}`);
    }
    // For browser tabs, activeTabId change causes Angular to show the correct
    // BrowserTabViewComponent (display:block) and hide others (display:none).

    if (persist) await this.persistOpenTabs();
    this.reportActiveTabToMain();
  }

  async addInternalTab(route: string, title: string, persist = true): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const tab: UiTab = {
      id,
      workspaceId: ws,
      kind: 'internal',
      url: `dev-lens:${route}`,
      title,
      internalRoute: route,
    };
    this.tabs.update((list) => [...list, tab]);
    await this.selectTab(id, false);
    if (persist) await this.persistOpenTabs();
    return id;
  }

  async addBrowserTab(url = 'about:blank', title = 'New Tab', persist = true): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const u = this.applyHttpsOnly(url);
    const tab: UiTab = { id, workspaceId: ws, kind: 'browser', url: u, title };
    this.tabs.update((list) => [...list, tab]);
    await this.selectTab(id, false);
    if (persist) await this.persistOpenTabs();
    return id;
  }

  async closeTab(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;
    this.tabLastSelectedAt.delete(tabId);
    this.suspendedBrowserIds.delete(tabId);
    if (this.splitView.secondaryTabId() === tabId) {
      this.splitView.secondaryTabId.set(null);
    }
    // BrowserTabViewComponent unmounts automatically via @for removing it from browserTabs().
    const list = this.tabs().filter((t) => t.id !== tabId);
    this.tabs.set(list);
    if (this.activeTabId() === tabId) {
      const next = list.find((t) => t.workspaceId === tab.workspaceId);
      if (next) await this.selectTab(next.id, false);
      else await this.addInternalTab('new-tab', 'New Tab', false);
    }
    await this.persistOpenTabs();
  }

  async closeOtherTabs(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;
    const closeIds = new Set(
      this.tabs()
        .filter((t) => t.workspaceId === tab.workspaceId && t.id !== tabId)
        .map((t) => t.id),
    );
    if (closeIds.size === 0) return;
    for (const id of closeIds) {
      this.tabLastSelectedAt.delete(id);
      this.suspendedBrowserIds.delete(id);
    }
    if (this.splitView.secondaryTabId() && closeIds.has(this.splitView.secondaryTabId()!)) {
      this.splitView.secondaryTabId.set(null);
    }
    this.tabs.update((list) => list.filter((t) => !closeIds.has(t.id)));
    await this.selectTab(tabId, false);
    await this.persistOpenTabs();
  }

  async navigateActive(url: string): Promise<void> {
    const tab = this.activeTab();
    if (!tab || tab.kind !== 'browser') return;
    const u = this.applyHttpsOnly(url);
    this.getActiveHandler()?.navigate(u);
    this.tabs.update((list) => list.map((t) => (t.id === tab.id ? { ...t, url: u, title: u } : t)));
    await this.persistOpenTabs();
    this.reportActiveTabToMain();
  }

  async goBack(): Promise<void> {
    this.getActiveHandler()?.back();
  }

  async goForward(): Promise<void> {
    this.getActiveHandler()?.forward();
  }

  async reload(): Promise<void> {
    this.getActiveHandler()?.reload();
  }

  stopActiveLoading(): void {
    this.getActiveHandler()?.stop?.();
  }

  /** Close every browser tab in the active workspace (internal tabs unchanged). */
  async closeAllBrowserTabsInActiveWorkspace(): Promise<void> {
    const ws = this.workspace.activeWorkspaceId();
    const ids = this.tabs()
      .filter((t) => t.workspaceId === ws && t.kind === 'browser')
      .map((t) => t.id);
    for (const id of ids) {
      await this.closeTab(id);
    }
  }

  async toggleDevtools(): Promise<void> {
    this.getActiveHandler()?.toggleDevtools();
  }

  /** Returns the Electron WebContentsId of the currently active guest webview, or undefined. */
  getActiveGuestWcId(): number | undefined {
    return this.getActiveHandler()?.getWebContentsId?.();
  }

  async inspectGuestElement(): Promise<void> {
    const id = this.activeTabId();
    if (!id) return;
    const h = this.webviewHandlers.get(id);
    const fn = h?.inspectElement;
    if (!fn) return;
    const p = this.inspectPointer.peek(id);
    fn.call(h, Math.max(0, Math.floor(p.x)), Math.max(0, Math.floor(p.y)));
  }

  async executeJavaScriptInActive(code: string): Promise<unknown> {
    const h = this.getActiveHandler();
    if (!h) return undefined;
    return h.executeJavaScript(code);
  }

  async duplicateTab(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab || tab.kind !== 'browser') return;
    await this.addBrowserTab(tab.url, `${tab.title} copy`);
  }

  async setPinned(tabId: string, pinned: boolean): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, pinned } : t)));
    await this.persistOpenTabs();
  }

  async moveTabToWorkspace(tabId: string, workspaceId: string): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, workspaceId } : t)));
    await this.persistOpenTabs();
  }

  reorderVisibleTabs(orderedIds: string[]): void {
    const ws = this.workspace.activeWorkspaceId();
    const otherWs = this.tabs().filter((t) => t.workspaceId !== ws);
    const idToTab = new Map(this.tabs().map((t) => [t.id, t]));
    const ordered = orderedIds.map((id) => idToTab.get(id)).filter((t): t is UiTab => !!t);
    const orderedSet = new Set(orderedIds);
    const sameWsTail = this.tabs().filter((t) => t.workspaceId === ws && !orderedSet.has(t.id));
    this.tabs.set([...otherWs, ...ordered, ...sameWsTail]);
    void this.persistOpenTabs();
  }

  async addTabGroup(title: string, color: string, tabIds?: string[]): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const groups = [
      ...(this.persisted.snapshot()?.tabGroups ?? []),
      { id, workspaceId: ws, title, color },
    ];
    await this.persisted.patch({ tabGroups: groups });
    if (tabIds?.length) {
      for (const tabId of tabIds) {
        await this.assignTabToGroup(tabId, id);
      }
    }
    return id;
  }

  async assignTabToGroup(tabId: string, groupId: string | null): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, groupId } : t)));
    await this.persistOpenTabs();
  }

  async renameGroup(groupId: string, title: string): Promise<void> {
    const groups = (this.persisted.snapshot()?.tabGroups ?? []).map((g) =>
      g.id === groupId ? { ...g, title } : g,
    );
    await this.persisted.patch({ tabGroups: groups });
  }

  async toggleGroupCollapsed(groupId: string): Promise<void> {
    const groups = (this.persisted.snapshot()?.tabGroups ?? []).map((g) =>
      g.id === groupId ? { ...g, collapsed: !g.collapsed } : g,
    );
    await this.persisted.patch({ tabGroups: groups });
  }

  /** Remove the group row and clear `groupId` on all tabs in that group. */
  async ungroupGroup(groupId: string): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const groups = snap.tabGroups.filter((g) => g.id !== groupId);
    this.tabs.update((list) =>
      list.map((t) => (t.groupId === groupId ? { ...t, groupId: null } : t)),
    );
    await this.persisted.patch({ tabGroups: groups, openTabs: this.tabs().map(toDto) });
  }

  /**
   * Remove a workspace, move its tabs and related data to another workspace.
   * @returns false if this was the last workspace (nothing done).
   */
  async deleteWorkspace(workspaceId: string): Promise<boolean> {
    const wss = this.workspace.workspaces();
    if (wss.length <= 1) return false;
    const target = wss.find((w) => w.id !== workspaceId)?.id;
    if (!target) return false;

    const snap = this.persisted.snapshot();
    if (!snap) return false;

    const wasActive = this.workspace.activeWorkspaceId() === workspaceId;
    const nextActive = wasActive ? target : this.workspace.activeWorkspaceId();
    const nextWorkspaces = wss.filter((w) => w.id !== workspaceId);
    const nextTabGroups = snap.tabGroups.filter((g) => g.workspaceId !== workspaceId);

    const sec = this.splitView.secondaryTabId();
    if (sec) {
      const secTab = this.tabs().find((t) => t.id === sec);
      if (secTab?.workspaceId === workspaceId) {
        this.splitView.secondaryTabId.set(null);
        this.splitView.enabled.set(false);
      }
    }

    this.tabs.update((list) =>
      list.map((t) =>
        t.workspaceId === workspaceId ? { ...t, workspaceId: target, groupId: null } : t,
      ),
    );

    const nextNotes = snap.notes.map((n) =>
      n.workspaceId === workspaceId ? { ...n, workspaceId: target } : n,
    );
    const nextSessions = snap.savedSessions.map((s) =>
      s.workspaceId === workspaceId ? { ...s, workspaceId: target } : s,
    );
    const nextRules = snap.automationRules.filter(
      (r) =>
        !(r.triggerType === 'workspace_active' && r.triggerValue.trim() === workspaceId) &&
        !(r.actionType === 'switch_workspace' && r.actionValue.trim() === workspaceId),
    );

    await this.persisted.patch({
      workspaces: nextWorkspaces,
      activeWorkspaceId: nextActive,
      tabGroups: nextTabGroups,
      openTabs: this.tabs().map(toDto),
      notes: nextNotes,
      savedSessions: nextSessions,
      automationRules: nextRules,
    });

    this.splitView.reconcile(this);

    if (wasActive) {
      const first = this.tabs().find((t) => t.workspaceId === nextActive);
      if (first) await this.selectTab(first.id, false);
      else await this.addInternalTab('new-tab', 'New Tab', false);
    }

    return true;
  }

  cycleTab(dir: 1 | -1): void {
    const vis = this.visibleTabs();
    const cur = this.activeTabId();
    const idx = vis.findIndex((t) => t.id === cur);
    if (vis.length === 0) return;
    const next = (idx + dir + vis.length) % vis.length;
    void this.selectTab(vis[next].id);
  }
}

export interface User {
  name: string;
}

import {
  NO_ERRORS_SCHEMA,
  Component,
  AfterViewInit,
  ElementRef,
  OnDestroy,
  OnInit,
  inject,
  input,
  viewChild,
} from '@angular/core';
import { RENDERER_INVOKE } from '@core/electron-ipc-channels';
import { workspaceBrowserPartition } from '@dev-lens/shared';
import { AutomationService } from '@core/services/automation.service';
import { ElectronBridgeService } from '@core/services/electron-bridge.service';
import { GuestLogService } from '@core/services/guest-log.service';
import { InspectPointerService } from '@core/services/inspect-pointer.service';
import type { UiTab, WebviewHandler } from '@core/services/tabs.service';
import { TabsService } from '@core/services/tabs.service';

const GUEST_CONSOLE_CHANNEL = 'dev-lens-console-log';

/**
 * Minimal type surface for the Electron `<webview>` DOM element.
 */
interface WebviewEl extends HTMLElement {
  src: string;
  loadURL(url: string): Promise<void>;
  getURL(): string;
  getTitle(): string;
  canGoBack(): boolean;
  canGoForward(): boolean;
  goBack(): void;
  goForward(): void;
  reload(): void;
  stop(): void;
  openDevTools(): void;
  closeDevTools(): void;
  isDevToolsOpened(): boolean;
  executeJavaScript(code: string, userGesture?: boolean): Promise<unknown>;
  inspectElement?(x: number, y: number): void;
  getWebContentsId?(): number;
}

@Component({
  selector: 'app-browser-tab-view',
  schemas: [NO_ERRORS_SCHEMA],
  /*
   * [attr.src] is set once (from initialSrc) so the webview starts loading
   * the URL immediately when inserted into the DOM, bypassing any dom-ready
   * timing issues.  For about:blank / new-tab pages we omit src so the
   * webview still initialises and fires dom-ready with no content yet.
   */
  template: `<webview
    #wv
    class="wv"
    [attr.src]="initialSrc"
    [attr.partition]="partitionAttr"
    allowpopups
  ></webview>`,
  styleUrl: './browser-tab-view.component.scss',
})
export class BrowserTabViewComponent implements OnInit, AfterViewInit, OnDestroy {
  readonly tab = input.required<UiTab>();

  private readonly wvRef = viewChild.required<ElementRef<HTMLElement>>('wv');
  private readonly bridge = inject(ElectronBridgeService);
  private readonly tabsSvc = inject(TabsService);
  private readonly guestLog = inject(GuestLogService);
  private readonly inspectPtr = inject(InspectPointerService);
  private readonly automation = inject(AutomationService);

  /**
   * Initial URL captured once in ngOnInit.
   * Kept as a plain field (not a signal) so the [attr.src] binding evaluates
   * to a stable value and Angular never re-applies it on later CD cycles.
   */
  initialSrc: string | null = null;

  /** True once the guest document has fired its first dom-ready. */
  private guestReady = false;
  private listenersRegistered = false;
  /** URL queued before dom-ready fired (for programmatic navigations). */
  private pendingNavigate: string | null = null;

  get partitionAttr(): string {
    return workspaceBrowserPartition(this.tab().workspaceId);
  }

  private get wv(): WebviewEl | null {
    const el = this.wvRef()?.nativeElement;
    return el ? (el as WebviewEl) : null;
  }

  private readonly onDomReady = (): void => {
    const wv = this.wv;
    if (!wv) return;
    this.guestReady = true;

    if (!this.listenersRegistered) {
      this.listenersRegistered = true;
      wv.addEventListener('did-navigate', this.onNavigate);
      wv.addEventListener('did-navigate-in-page', this.onNavigate);
      wv.addEventListener('page-title-updated', this.onTitle);
      wv.addEventListener('new-window', this.onNewWindow);
      wv.addEventListener('mousemove', this.onGuestMouseMove);
      wv.addEventListener('did-start-loading', this.onStartLoading);
      wv.addEventListener('did-stop-loading', this.onStopLoading);
      wv.addEventListener('did-fail-load', this.onStopLoading);
    }
    this.syncGuestNav();

    // Flush a navigate that arrived before the guest was ready.
    // (The initial URL is already loading via the src attribute.)
    if (this.pendingNavigate) {
      const url = this.pendingNavigate;
      this.pendingNavigate = null;
      void wv.loadURL(url);
    }
  };

  private readonly onNavigate = (e: Event): void => {
    const url = (e as unknown as { url?: string }).url ?? this.wv?.getURL() ?? '';
    const title = this.wv?.getTitle() ?? url;
    this.tabsSvc.updateTabState(this.tab().id, url, title);
    if (url.startsWith('http://') || url.startsWith('https://')) {
      void this.bridge.invoke(RENDERER_INVOKE.HISTORY_APPEND, { url, title: title || url });
    }
    this.automation.onBrowserUrl(url);
    this.syncGuestNav();
  };

  private readonly syncGuestNav = (): void => {
    const wv = this.wv;
    if (!wv || !this.guestReady) return;
    this.tabsSvc.setGuestNavState(this.tab().id, {
      canBack: wv.canGoBack(),
      canFwd: wv.canGoForward(),
    });
  };

  private readonly onStartLoading = (): void => {
    this.tabsSvc.setGuestNavState(this.tab().id, { loading: true });
  };

  private readonly onStopLoading = (): void => {
    this.tabsSvc.setGuestNavState(this.tab().id, { loading: false });
    this.syncGuestNav();
  };

  private readonly onGuestMouseMove = (e: MouseEvent): void => {
    const wv = this.wv;
    if (!wv) return;
    const r = wv.getBoundingClientRect();
    this.inspectPtr.record(this.tab().id, e.clientX - r.left, e.clientY - r.top);
  };

  private readonly onTitle = (e: Event): void => {
    const title = (e as unknown as { title?: string }).title ?? '';
    const url = this.wv?.getURL() ?? this.tab().url;
    if (title) this.tabsSvc.updateTabState(this.tab().id, url, title);
    this.syncGuestNav();
  };

  private readonly onNewWindow = (e: Event): void => {
    const url = (e as unknown as { url?: string }).url ?? '';
    if (url) void this.bridge.invoke(RENDERER_INVOKE.SHELL_OPEN_EXTERNAL, { url });
  };

  private readonly onGuestIpc = (e: Event): void => {
    const ev = e as unknown as { channel?: string; args?: unknown[] };
    if (ev.channel !== GUEST_CONSOLE_CHANNEL) return;
    const payload = ev.args?.[0] as { level?: string; msg?: string; t?: number } | undefined;
    if (!payload) return;
    this.guestLog.pushGuest(this.tab().id, payload);
  };

  ngOnInit(): void {
    // Capture the initial URL once so the [attr.src] binding stays stable.
    const url = this.tab().url;
    this.initialSrc = url && url !== 'about:blank' ? url : null;

    void this.bridge.invoke(RENDERER_INVOKE.SESSION_INIT, { partition: this.partitionAttr });

    const handler: WebviewHandler = {
      navigate: (target) => {
        if (!this.guestReady) {
          this.pendingNavigate = target;
          return;
        }
        void this.wv?.loadURL(target);
      },
      back: () => {
        if (this.guestReady) this.wv?.goBack();
      },
      forward: () => {
        if (this.guestReady) this.wv?.goForward();
      },
      reload: () => {
        if (this.guestReady) this.wv?.reload();
      },
      stop: () => {
        if (!this.guestReady) return;
        const w = this.wv;
        if (w && typeof w.stop === 'function') w.stop();
      },
      toggleDevtools: () => {
        if (!this.guestReady) return;
        const wv = this.wv;
        if (!wv) return;
        if (wv.isDevToolsOpened()) wv.closeDevTools();
        else wv.openDevTools();
      },
      executeJavaScript: (code: string) => {
        if (!this.guestReady || !this.wv) return Promise.resolve(undefined);
        return this.wv.executeJavaScript(code);
      },
      suspendToBlank: () => {
        if (!this.guestReady || !this.wv) return;
        void this.wv.loadURL('about:blank');
      },
      inspectElement: (x: number, y: number) => {
        if (!this.guestReady || !this.wv) return;
        this.wv.inspectElement?.(x, y);
      },
      getWebContentsId: () => {
        const wv = this.wv;
        if (!this.guestReady || !wv) return undefined;
        const id = wv.getWebContentsId?.();
        return typeof id === 'number' ? id : undefined;
      },
    };
    this.tabsSvc.registerWebview(this.tab().id, handler);
  }

  ngAfterViewInit(): void {
    const wv = this.wv;
    if (!wv) return;
    wv.addEventListener('ipc-message', this.onGuestIpc);
    /*
     * dom-ready fires:
     *  – for src="" navigations: when the initial page's DOM is ready
     *  – for about:blank tabs: very quickly after the guest is attached
     * We keep the listener alive (no `once`) so dom-ready can fire again if
     * the guest process restarts (rare but possible on heavy pages).
     */
    wv.addEventListener('dom-ready', this.onDomReady);
  }

  ngOnDestroy(): void {
    const wv = this.wv;
    if (wv) {
      wv.removeEventListener('ipc-message', this.onGuestIpc);
      wv.removeEventListener('dom-ready', this.onDomReady);
      wv.removeEventListener('did-navigate', this.onNavigate);
      wv.removeEventListener('did-navigate-in-page', this.onNavigate);
      wv.removeEventListener('page-title-updated', this.onTitle);
      wv.removeEventListener('new-window', this.onNewWindow);
      wv.removeEventListener('mousemove', this.onGuestMouseMove);
      wv.removeEventListener('did-start-loading', this.onStartLoading);
      wv.removeEventListener('did-stop-loading', this.onStopLoading);
      wv.removeEventListener('did-fail-load', this.onStopLoading);
    }
    this.guestLog.clearTab(this.tab().id);
    this.tabsSvc.unregisterWebview(this.tab().id);
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { Router } from '@angular/router';
import { IPC_CHANNELS, IPC_EVENTS, type PersistedTabDTO } from '@dev-lens/shared';
import { ElectronBridgeService } from './electron-bridge.service';
import { InspectPointerService } from './inspect-pointer.service';
import { PersistedStateService } from './persisted-state.service';
import { SplitViewService } from './split-view.service';
import { WorkspaceService } from './workspace.service';

export interface UiTab {
  id: string;
  workspaceId: string;
  kind: 'browser' | 'internal';
  url: string;
  title: string;
  internalRoute?: string;
  pinned?: boolean;
  groupId?: string | null;
}

export interface WebviewHandler {
  navigate(url: string): void;
  back(): void;
  forward(): void;
  reload(): void;
  stop?: () => void;
  toggleDevtools(): void;
  executeJavaScript(code: string): Promise<unknown>;
  /** Unload guest to about:blank to reduce memory when tab is auto-suspended. */
  suspendToBlank(): void;
  /** DevTools “pick element” at guest viewport coordinates. */
  inspectElement?(x: number, y: number): void;
  /** Returns the Electron WebContentsId of the guest webview for DevTools attachment. */
  getWebContentsId?(): number | undefined;
}

function toUi(dto: PersistedTabDTO): UiTab {
  return {
    id: dto.id,
    workspaceId: dto.workspaceId,
    kind: dto.kind,
    url: dto.url,
    title: dto.title,
    internalRoute: dto.internalRoute,
    pinned: dto.pinned,
    groupId: dto.groupId ?? null,
  };
}

function toDto(t: UiTab): PersistedTabDTO {
  return {
    id: t.id,
    workspaceId: t.workspaceId,
    kind: t.kind,
    url: t.url,
    title: t.title,
    internalRoute: t.internalRoute,
    pinned: t.pinned,
    groupId: t.groupId,
  };
}

@Injectable({ providedIn: 'root' })
export class TabsService {
  private readonly bridge = inject(ElectronBridgeService);
  private readonly persisted = inject(PersistedStateService);
  private readonly workspace = inject(WorkspaceService);
  private readonly splitView = inject(SplitViewService);
  private readonly router = inject(Router);

  private readonly tabLastSelectedAt = new Map<string, number>();
  private readonly suspendedBrowserIds = new Set<string>();
  private suspendTimer: ReturnType<typeof setInterval> | null = null;

  readonly tabs = signal<UiTab[]>([]);
  readonly activeTabId = signal<string | null>(null);

  readonly visibleTabs = computed(() =>
    this.tabs().filter((t) => t.workspaceId === this.workspace.activeWorkspaceId()),
  );

  readonly activeTab = computed(() => {
    const id = this.activeTabId();
    if (!id) return undefined;
    return this.tabs().find((t) => t.id === id);
  });

  /** Browser tabs visible to Angular `@for` → `BrowserTabViewComponent`. */
  readonly browserTabs = computed(() => this.tabs().filter((t) => t.kind === 'browser'));

  // ── Webview handler registry ───────────────────────────────────────────────
  private readonly webviewHandlers = new Map<string, WebviewHandler>();
  private readonly inspectPointer = inject(InspectPointerService);

  /** Per-tab guest navigation state (updated from BrowserTabViewComponent). */
  private readonly guestNavState = signal<
    Record<string, { canBack: boolean; canFwd: boolean; loading: boolean }>
  >({});

  readonly activeGuestNav = computed(() => {
    const id = this.activeTabId();
    if (!id) return { canBack: false, canFwd: false, loading: false };
    return this.guestNavState()[id] ?? { canBack: false, canFwd: false, loading: false };
  });

  setGuestNavState(
    tabId: string,
    patch: Partial<{ canBack: boolean; canFwd: boolean; loading: boolean }>,
  ): void {
    this.guestNavState.update((m) => {
      const cur = m[tabId] ?? { canBack: false, canFwd: false, loading: false };
      return { ...m, [tabId]: { ...cur, ...patch } };
    });
  }

  registerWebview(tabId: string, handler: WebviewHandler): void {
    this.webviewHandlers.set(tabId, handler);
  }

  unregisterWebview(tabId: string): void {
    this.webviewHandlers.delete(tabId);
    this.guestNavState.update((m) => {
      const rest = { ...m };
      delete rest[tabId];
      return rest;
    });
  }

  private getActiveHandler(): WebviewHandler | undefined {
    const id = this.activeTabId();
    return id ? this.webviewHandlers.get(id) : undefined;
  }

  private applyHttpsOnly(url: string): string {
    if (!this.persisted.snapshot()?.settings.httpsOnlyMode) return url;
    const t = url.trim();
    if (t.toLowerCase().startsWith('http://')) return `https://${t.slice(7)}`;
    return url;
  }

  private reportActiveTabToMain(): void {
    if (!this.bridge.isElectron) return;
    const t = this.activeTab();
    if (!t || t.kind !== 'browser') {
      void this.bridge.invoke(IPC_CHANNELS.TABS_REPORT_ACTIVE, { url: '', title: '' });
      return;
    }
    void this.bridge.invoke(IPC_CHANNELS.TABS_REPORT_ACTIVE, { url: t.url, title: t.title });
  }

  // ── Reactive state update from BrowserTabViewComponent ────────────────────
  updateTabState(tabId: string, url: string, title: string): void {
    this.tabs.update((list) =>
      list.map((t) =>
        t.id === tabId && t.kind === 'browser'
          ? { ...t, url: url || t.url, title: title || url || t.title }
          : t,
      ),
    );
    if (tabId === this.activeTabId()) this.reportActiveTabToMain();
  }

  // ── Lifecycle ──────────────────────────────────────────────────────────────
  private listenersBound = false;

  bindMainProcessEvents(): void {
    if (this.listenersBound || !this.bridge.isElectron) return;
    this.listenersBound = true;
    this.bridge.on(IPC_EVENTS.PLUGIN_OPEN_URL, (raw) => {
      const p = raw as { url?: string; title?: string };
      if (!p.url?.trim()) return;
      void this.addBrowserTab(p.url, p.title || p.url);
    });
    // Blocker stats arrive via IPC_EVENTS.BLOCKER_STATS – handled in TopBarComponent.
    // Tab updates now come directly from BrowserTabViewComponent (no main-process round-trip).
    void this.bridge.invoke(IPC_CHANNELS.BLOCKER_GET_STATS);
    if (!this.suspendTimer) {
      this.suspendTimer = setInterval(() => this.applyAutoSuspend(), 30_000);
    }
  }

  isBrowserTabSuspended(tabId: string): boolean {
    return this.suspendedBrowserIds.has(tabId);
  }

  private applyAutoSuspend(): void {
    const mins = this.persisted.snapshot()?.settings.tabSuspendAfterMinutes ?? 0;
    if (!mins) {
      this.suspendedBrowserIds.clear();
      return;
    }
    const ms = mins * 60 * 1000;
    const now = Date.now();
    const active = this.activeTabId();
    const sec = this.splitView.enabled() ? this.splitView.secondaryTabId() : null;
    const ws = this.workspace.activeWorkspaceId();
    for (const t of this.tabs()) {
      if (t.workspaceId !== ws || t.kind !== 'browser') continue;
      if (t.id === active || t.id === sec) continue;
      const last = this.tabLastSelectedAt.get(t.id) ?? 0;
      if (now - last < ms) continue;
      if (this.suspendedBrowserIds.has(t.id)) continue;
      this.suspendedBrowserIds.add(t.id);
      this.webviewHandlers.get(t.id)?.suspendToBlank();
    }
  }

  async bootstrap(): Promise<void> {
    if (!this.bridge.isElectron) return;
    await this.persisted.hydrate();
    const snap = this.persisted.snapshot();
    if (!snap) return;

    if (snap.openTabs.length > 0) {
      // Restore tab state — BrowserTabViewComponents handle their own URL loading.
      this.tabs.set(snap.openTabs.map(toUi));
      const now = Date.now();
      for (const t of snap.openTabs) this.tabLastSelectedAt.set(t.id, now);
      const inWs = snap.openTabs.filter((t) => t.workspaceId === snap.activeWorkspaceId);
      const pick = inWs[0] ?? snap.openTabs[0];
      if (pick) await this.selectTab(pick.id, false);
    } else {
      await this.addInternalTab('new-tab', 'New Tab', false);
    }
  }

  async persistOpenTabs(): Promise<void> {
    await this.persisted.patch({ openTabs: this.tabs().map(toDto) });
  }

  async selectTab(tabId: string, persist = true): Promise<void> {
    this.activeTabId.set(tabId);
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;

    this.tabLastSelectedAt.set(tabId, Date.now());
    if (tab.kind === 'browser' && this.suspendedBrowserIds.has(tabId)) {
      this.suspendedBrowserIds.delete(tabId);
      this.webviewHandlers.get(tabId)?.navigate(tab.url);
    }

    if (tab.kind === 'internal') {
      const route = tab.internalRoute ?? 'new-tab';
      await this.router.navigateByUrl(`/${route}`);
    }
    // For browser tabs, activeTabId change causes Angular to show the correct
    // BrowserTabViewComponent (display:block) and hide others (display:none).

    if (persist) await this.persistOpenTabs();
    this.reportActiveTabToMain();
  }

  async addInternalTab(route: string, title: string, persist = true): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const tab: UiTab = {
      id,
      workspaceId: ws,
      kind: 'internal',
      url: `dev-lens:${route}`,
      title,
      internalRoute: route,
    };
    this.tabs.update((list) => [...list, tab]);
    await this.selectTab(id, false);
    if (persist) await this.persistOpenTabs();
    return id;
  }

  async addBrowserTab(url = 'about:blank', title = 'New Tab', persist = true): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const u = this.applyHttpsOnly(url);
    const tab: UiTab = { id, workspaceId: ws, kind: 'browser', url: u, title };
    this.tabs.update((list) => [...list, tab]);
    await this.selectTab(id, false);
    if (persist) await this.persistOpenTabs();
    return id;
  }

  async closeTab(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;
    this.tabLastSelectedAt.delete(tabId);
    this.suspendedBrowserIds.delete(tabId);
    if (this.splitView.secondaryTabId() === tabId) {
      this.splitView.secondaryTabId.set(null);
    }
    // BrowserTabViewComponent unmounts automatically via @for removing it from browserTabs().
    const list = this.tabs().filter((t) => t.id !== tabId);
    this.tabs.set(list);
    if (this.activeTabId() === tabId) {
      const next = list.find((t) => t.workspaceId === tab.workspaceId);
      if (next) await this.selectTab(next.id, false);
      else await this.addInternalTab('new-tab', 'New Tab', false);
    }
    await this.persistOpenTabs();
  }

  async closeOtherTabs(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab) return;
    const closeIds = new Set(
      this.tabs()
        .filter((t) => t.workspaceId === tab.workspaceId && t.id !== tabId)
        .map((t) => t.id),
    );
    if (closeIds.size === 0) return;
    for (const id of closeIds) {
      this.tabLastSelectedAt.delete(id);
      this.suspendedBrowserIds.delete(id);
    }
    if (this.splitView.secondaryTabId() && closeIds.has(this.splitView.secondaryTabId()!)) {
      this.splitView.secondaryTabId.set(null);
    }
    this.tabs.update((list) => list.filter((t) => !closeIds.has(t.id)));
    await this.selectTab(tabId, false);
    await this.persistOpenTabs();
  }

  async navigateActive(url: string): Promise<void> {
    const tab = this.activeTab();
    if (!tab || tab.kind !== 'browser') return;
    const u = this.applyHttpsOnly(url);
    this.getActiveHandler()?.navigate(u);
    this.tabs.update((list) => list.map((t) => (t.id === tab.id ? { ...t, url: u, title: u } : t)));
    await this.persistOpenTabs();
    this.reportActiveTabToMain();
  }

  async goBack(): Promise<void> {
    this.getActiveHandler()?.back();
  }

  async goForward(): Promise<void> {
    this.getActiveHandler()?.forward();
  }

  async reload(): Promise<void> {
    this.getActiveHandler()?.reload();
  }

  stopActiveLoading(): void {
    this.getActiveHandler()?.stop?.();
  }

  /** Close every browser tab in the active workspace (internal tabs unchanged). */
  async closeAllBrowserTabsInActiveWorkspace(): Promise<void> {
    const ws = this.workspace.activeWorkspaceId();
    const ids = this.tabs()
      .filter((t) => t.workspaceId === ws && t.kind === 'browser')
      .map((t) => t.id);
    for (const id of ids) {
      await this.closeTab(id);
    }
  }

  async toggleDevtools(): Promise<void> {
    this.getActiveHandler()?.toggleDevtools();
  }

  /** Returns the Electron WebContentsId of the currently active guest webview, or undefined. */
  getActiveGuestWcId(): number | undefined {
    return this.getActiveHandler()?.getWebContentsId?.();
  }

  async inspectGuestElement(): Promise<void> {
    const id = this.activeTabId();
    if (!id) return;
    const h = this.webviewHandlers.get(id);
    const fn = h?.inspectElement;
    if (!fn) return;
    const p = this.inspectPointer.peek(id);
    fn.call(h, Math.max(0, Math.floor(p.x)), Math.max(0, Math.floor(p.y)));
  }

  async executeJavaScriptInActive(code: string): Promise<unknown> {
    const h = this.getActiveHandler();
    if (!h) return undefined;
    return h.executeJavaScript(code);
  }

  async duplicateTab(tabId: string): Promise<void> {
    const tab = this.tabs().find((t) => t.id === tabId);
    if (!tab || tab.kind !== 'browser') return;
    await this.addBrowserTab(tab.url, `${tab.title} copy`);
  }

  async setPinned(tabId: string, pinned: boolean): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, pinned } : t)));
    await this.persistOpenTabs();
  }

  async moveTabToWorkspace(tabId: string, workspaceId: string): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, workspaceId } : t)));
    await this.persistOpenTabs();
  }

  reorderVisibleTabs(orderedIds: string[]): void {
    const ws = this.workspace.activeWorkspaceId();
    const otherWs = this.tabs().filter((t) => t.workspaceId !== ws);
    const idToTab = new Map(this.tabs().map((t) => [t.id, t]));
    const ordered = orderedIds.map((id) => idToTab.get(id)).filter((t): t is UiTab => !!t);
    const orderedSet = new Set(orderedIds);
    const sameWsTail = this.tabs().filter((t) => t.workspaceId === ws && !orderedSet.has(t.id));
    this.tabs.set([...otherWs, ...ordered, ...sameWsTail]);
    void this.persistOpenTabs();
  }

  async addTabGroup(title: string, color: string, tabIds?: string[]): Promise<string> {
    const id = crypto.randomUUID();
    const ws = this.workspace.activeWorkspaceId();
    const groups = [
      ...(this.persisted.snapshot()?.tabGroups ?? []),
      { id, workspaceId: ws, title, color },
    ];
    await this.persisted.patch({ tabGroups: groups });
    if (tabIds?.length) {
      for (const tabId of tabIds) {
        await this.assignTabToGroup(tabId, id);
      }
    }
    return id;
  }

  async assignTabToGroup(tabId: string, groupId: string | null): Promise<void> {
    this.tabs.update((list) => list.map((t) => (t.id === tabId ? { ...t, groupId } : t)));
    await this.persistOpenTabs();
  }

  async renameGroup(groupId: string, title: string): Promise<void> {
    const groups = (this.persisted.snapshot()?.tabGroups ?? []).map((g) =>
      g.id === groupId ? { ...g, title } : g,
    );
    await this.persisted.patch({ tabGroups: groups });
  }

  async toggleGroupCollapsed(groupId: string): Promise<void> {
    const groups = (this.persisted.snapshot()?.tabGroups ?? []).map((g) =>
      g.id === groupId ? { ...g, collapsed: !g.collapsed } : g,
    );
    await this.persisted.patch({ tabGroups: groups });
  }

  /** Remove the group row and clear `groupId` on all tabs in that group. */
  async ungroupGroup(groupId: string): Promise<void> {
    const snap = this.persisted.snapshot();
    if (!snap) return;
    const groups = snap.tabGroups.filter((g) => g.id !== groupId);
    this.tabs.update((list) =>
      list.map((t) => (t.groupId === groupId ? { ...t, groupId: null } : t)),
    );
    await this.persisted.patch({ tabGroups: groups, openTabs: this.tabs().map(toDto) });
  }

  /**
   * Remove a workspace, move its tabs and related data to another workspace.
   * @returns false if this was the last workspace (nothing done).
   */
  async deleteWorkspace(workspaceId: string): Promise<boolean> {
    const wss = this.workspace.workspaces();
    if (wss.length <= 1) return false;
    const target = wss.find((w) => w.id !== workspaceId)?.id;
    if (!target) return false;

    const snap = this.persisted.snapshot();
    if (!snap) return false;

    const wasActive = this.workspace.activeWorkspaceId() === workspaceId;
    const nextActive = wasActive ? target : this.workspace.activeWorkspaceId();
    const nextWorkspaces = wss.filter((w) => w.id !== workspaceId);
    const nextTabGroups = snap.tabGroups.filter((g) => g.workspaceId !== workspaceId);

    const sec = this.splitView.secondaryTabId();
    if (sec) {
      const secTab = this.tabs().find((t) => t.id === sec);
      if (secTab?.workspaceId === workspaceId) {
        this.splitView.secondaryTabId.set(null);
        this.splitView.enabled.set(false);
      }
    }

    this.tabs.update((list) =>
      list.map((t) =>
        t.workspaceId === workspaceId ? { ...t, workspaceId: target, groupId: null } : t,
      ),
    );

    const nextNotes = snap.notes.map((n) =>
      n.workspaceId === workspaceId ? { ...n, workspaceId: target } : n,
    );
    const nextSessions = snap.savedSessions.map((s) =>
      s.workspaceId === workspaceId ? { ...s, workspaceId: target } : s,
    );
    const nextRules = snap.automationRules.filter(
      (r) =>
        !(r.triggerType === 'workspace_active' && r.triggerValue.trim() === workspaceId) &&
        !(r.actionType === 'switch_workspace' && r.actionValue.trim() === workspaceId),
    );

    await this.persisted.patch({
      workspaces: nextWorkspaces,
      activeWorkspaceId: nextActive,
      tabGroups: nextTabGroups,
      openTabs: this.tabs().map(toDto),
      notes: nextNotes,
      savedSessions: nextSessions,
      automationRules: nextRules,
    });

    this.splitView.reconcile(this);

    if (wasActive) {
      const first = this.tabs().find((t) => t.workspaceId === nextActive);
      if (first) await this.selectTab(first.id, false);
      else await this.addInternalTab('new-tab', 'New Tab', false);
    }

    return true;
  }

  cycleTab(dir: 1 | -1): void {
    const vis = this.visibleTabs();
    const cur = this.activeTabId();
    const idx = vis.findIndex((t) => t.id === cur);
    if (vis.length === 0) return;
    const next = (idx + dir + vis.length) % vis.length;
    void this.selectTab(vis[next].id);
  }
}

