import { Injectable, inject, signal } from '@angular/core';
import { IPC_CHANNELS, type DevLensStoreSnapshot } from '@dev-lens/shared';
import { ElectronBridgeService } from './electron-bridge.service';

@Injectable({ providedIn: 'root' })
export class PersistedStateService {
  private readonly bridge = inject(ElectronBridgeService);

  readonly snapshot = signal<DevLensStoreSnapshot | null>(null);

  async hydrate(): Promise<void> {
    if (!this.bridge.isElectron) return;
    const data = await this.bridge.invoke<DevLensStoreSnapshot>(IPC_CHANNELS.STORE_GET);
    this.snapshot.set(data);
  }

  async patch(partial: Partial<DevLensStoreSnapshot>): Promise<void> {
    if (!this.bridge.isElectron) return;
    const res = await this.bridge.invoke<{ ok?: boolean; error?: string }>(
      IPC_CHANNELS.STORE_PATCH,
      partial,
    );
    if (res && typeof res === 'object' && 'ok' in res && res.ok === false) {
      throw new Error(res.error ?? 'Store update rejected');
    }
    await this.hydrate();
  }
}

import { Injectable, inject, signal } from '@angular/core';
import { IPC_CHANNELS } from '@dev-lens/shared';
import { ElectronBridgeService } from './electron-bridge.service';

export interface DiscoveredPluginUi {
  id: string;
  name: string;
  version: string;
  permissions: string[];
  sidebarTitle: string;
  entryBaseUrl: string;
  bundled: boolean;
  enabled: boolean;
}

@Injectable({ providedIn: 'root' })
export class PluginRuntimeService {
  private readonly bridge = inject(ElectronBridgeService);

  /** Plugins that are enabled (shown in sidebar). */
  readonly sidebarPlugins = signal<DiscoveredPluginUi[]>([]);
  /** Full discovery list (Settings UI). */
  readonly allPlugins = signal<DiscoveredPluginUi[]>([]);

  async refresh(): Promise<void> {
    if (!this.bridge.isElectron) {
      this.sidebarPlugins.set([]);
      this.allPlugins.set([]);
      return;
    }
    const r = await this.bridge.invoke<{ plugins: DiscoveredPluginUi[] }>(
      IPC_CHANNELS.PLUGIN_DISCOVER,
    );
    const list = r.plugins ?? [];
    this.allPlugins.set(list);
    this.sidebarPlugins.set(list.filter((p) => p.enabled));
  }

  async setEnabled(id: string, enabled: boolean): Promise<void> {
    if (!this.bridge.isElectron) return;
    const res = await this.bridge.invoke<{ ok?: boolean }>(IPC_CHANNELS.PLUGIN_SET_ENABLED, {
      id,
      enabled,
    });
    if (res && typeof res === 'object' && 'ok' in res && res.ok === false) return;
    await this.refresh();
  }
}

import { Injectable, signal } from '@angular/core';

/**
 * Coordinates sidebar drag-resize with any native overlay (e.g. the DevTools
 * BrowserView) that needs to be hidden/restored around the drag.
 *
 * Components that manage native overlays call `registerOverlayCallbacks()` to
 * supply hide/restore functions.  The right-sidebar calls `beginResize()` and
 * `endResize()` which invoke those callbacks SYNCHRONOUSLY — before any
 * mousemove event can reach the native overlay and steal pointer capture.
 */
@Injectable({ providedIn: 'root' })
export class ResizeStateService {
  readonly isSidebarResizing = signal(false);

  private hideCallback: (() => void) | null = null;
  private restoreCallback: (() => void) | null = null;

  registerOverlayCallbacks(hide: () => void, restore: () => void): void {
    this.hideCallback = hide;
    this.restoreCallback = restore;
  }

  /**
   * Called on mousedown — hides the overlay immediately (synchronous IPC fire)
   * and sets the resizing signal so Angular effects can also react.
   */
  beginResize(): void {
    this.isSidebarResizing.set(true);
    this.hideCallback?.();
  }

  /**
   * Called on mouseup — restores the overlay to the new position and clears
   * the resizing signal.
   */
  endResize(): void {
    this.isSidebarResizing.set(false);
    this.restoreCallback?.();
  }
}

import { Injectable, inject } from '@angular/core';
import { PersistedStateService } from './persisted-state.service';

/** Default shortcuts (canonical combo string: modifiers + key, lowercase). */
export const SHORTCUT_DEFAULTS: Record<string, string> = {
  spotlight: 'ctrl+k',
  newTab: 'ctrl+t',
  closeTab: 'ctrl+w',
  cycleTabNext: 'ctrl+tab',
  cycleTabPrev: 'ctrl+shift+tab',
  toggleSplit: 'ctrl+shift+\\',
  focusMode: 'ctrl+alt+f',
  toggleDevtools: 'ctrl+shift+i',
  inspectElement: 'ctrl+shift+c',
};

export function normalizeShortcutBinding(raw: string): string {
  return raw
    .trim()
    .toLowerCase()
    .split(/\+/)
    .map((p) => p.trim())
    .filter(Boolean)
    .sort((a, b) => {
      const order = (x: string): number => {
        if (x === 'ctrl' || x === 'meta' || x === 'cmd') return 0;
        if (x === 'alt') return 1;
        if (x === 'shift') return 2;
        return 3;
      };
      const d = order(a) - order(b);
      return d !== 0 ? d : a.localeCompare(b);
    })
    .map((p) => (p === 'meta' || p === 'cmd' ? 'ctrl' : p))
    .join('+');
}

function comboFromEvent(ev: KeyboardEvent): string | null {
  const keyRaw = ev.key;
  const k =
    keyRaw === 'Tab'
      ? 'tab'
      : keyRaw === ' '
        ? 'space'
        : keyRaw === '\\' || keyRaw === '|'
          ? '\\'
          : keyRaw.length === 1
            ? keyRaw.toLowerCase()
            : keyRaw.toLowerCase();

  const parts: string[] = [];
  if (ev.ctrlKey || ev.metaKey) parts.push('ctrl');
  if (ev.altKey) parts.push('alt');
  if (ev.shiftKey) parts.push('shift');
  parts.push(k);
  return normalizeShortcutBinding(parts.join('+'));
}

/** Effective bindings: defaults overridden by `custom`. */
export function buildMergedShortcutBindings(
  custom: Record<string, string>,
): Record<string, string> {
  const merged: Record<string, string> = { ...SHORTCUT_DEFAULTS };
  for (const [action, bound] of Object.entries(custom)) {
    if (typeof bound === 'string' && bound.trim()) merged[action] = bound;
  }
  return merged;
}

/** Human-readable lines listing actions that share the same combo. */
export function describeShortcutConflicts(merged: Record<string, string>): string[] {
  const byCombo = new Map<string, string[]>();
  for (const [action, bound] of Object.entries(merged)) {
    const c = normalizeShortcutBinding(bound);
    if (!byCombo.has(c)) byCombo.set(c, []);
    byCombo.get(c)!.push(action);
  }
  const out: string[] = [];
  for (const actions of byCombo.values()) {
    if (actions.length > 1) out.push(`${actions.join(' ↔ ')} share the same combo`);
  }
  return out;
}

@Injectable({ providedIn: 'root' })
export class ShortcutRegistryService {
  private readonly persisted = inject(PersistedStateService);

  /** Returns shortcut action id if the event matches a merged binding, else null. */
  matchAction(ev: KeyboardEvent): string | null {
    const combo = comboFromEvent(ev);
    if (!combo) return null;
    const custom = this.persisted.snapshot()?.settings.shortcutBindings ?? {};
    const merged = buildMergedShortcutBindings(custom);
    for (const [action, bound] of Object.entries(merged)) {
      if (normalizeShortcutBinding(bound) === combo) return action;
    }
    return null;
  }

  /** Human-readable combo for Settings (uses Ctrl for display on all platforms). */
  displayCombo(bound: string): string {
    return bound
      .split('+')
      .map((p) => (p === 'ctrl' ? 'Ctrl' : p.charAt(0).toUpperCase() + p.slice(1)))
      .join('+');
  }
}

import { Injectable, effect, inject, signal } from '@angular/core';
import { FeatureFlagsService } from './feature-flags.service';
import type { TabsService } from './tabs.service';

/**
 * Split-view: two browser panes side by side (primary = active tab, secondary = chosen tab).
 */
@Injectable({ providedIn: 'root' })
export class SplitViewService {
  private readonly features = inject(FeatureFlagsService);

  readonly enabled = signal(false);

  /** Fraction of width for the primary (left) pane, 0–1. */
  readonly primaryRatio = signal(0.5);

  /** Second browser tab shown in the right pane when split is on. */
  readonly secondaryTabId = signal<string | null>(null);

  constructor() {
    effect(() => {
      if (!this.features.flags().splitView && this.enabled()) {
        this.enabled.set(false);
        this.secondaryTabId.set(null);
      }
    });
  }

  attemptToggle(tabs: TabsService): void {
    if (!this.features.flags().splitView) {
      if (this.enabled()) {
        this.enabled.set(false);
        this.secondaryTabId.set(null);
      }
      return;
    }
    if (this.enabled()) {
      this.enabled.set(false);
      this.secondaryTabId.set(null);
      return;
    }
    const browsers = tabs.visibleTabs().filter((t) => t.kind === 'browser');
    if (browsers.length < 2) return;
    const activeId = tabs.activeTabId();
    const other = browsers.find((t) => t.id !== activeId);
    if (!other) return;
    this.secondaryTabId.set(other.id);
    this.enabled.set(true);
  }

  reconcile(tabs: TabsService): void {
    if (!this.enabled()) return;
    const active = tabs.activeTab();
    const sec = this.secondaryTabId();
    const browsers = tabs.visibleTabs().filter((t) => t.kind === 'browser');
    if (browsers.length < 2) {
      this.enabled.set(false);
      this.secondaryTabId.set(null);
      return;
    }
    if (
      active?.kind === 'browser' &&
      sec &&
      sec !== active.id &&
      browsers.some((t) => t.id === sec)
    ) {
      return;
    }
    const pick = browsers.find((t) => t.id !== active?.id) ?? null;
    this.secondaryTabId.set(pick?.id ?? null);
    if (!pick) this.enabled.set(false);
  }

  setRatio(ratio: number): void {
    const r = Math.min(0.85, Math.max(0.15, ratio));
    this.primaryRatio.set(r);
  }
}

