    } @else if (kind() === 'array') {
      <div class="jn-block">
        <button type="button" class="jn-toggle" (click)="open.set(!open())">
          {{ open() ? '▼' : '▶' }} [{{ arrLen() }}]
        </button>
        @if (open()) {
          <div class="jn-children">
            @for (item of arrVal(); track $index) {
              <div class="jn-row">
                <span class="jn-idx">{{ $index }}</span>
