                    viewBox="0 0 16 16"
                  >
                    <circle cx="8" cy="8" r="6" />
                    <path d="M8 4v4l3 2" />
                  </svg>
                }
                @case ('readlater') {
                  <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="1.5"
                    viewBox="0 0 16 16"
                  >
                    <path d="M4 2.5h8a1 1 0 011 1v10l-5-3-5 3v-10a1 1 0 011-1z" />
                  </svg>
                }
                @case ('perf') {
                  <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="1.5"
                    viewBox="0 0 16 16"
                  >
                    <path d="M3 13h10M4 9l3-3 2 2 3-4" />
                  </svg>
                }
                @case ('json') {
                  <svg
                    width="16"
                    height="16"
                    fill="none"
                    stroke="currentColor"
                    stroke-width="1.5"
                    viewBox="0 0 16 16"
                  >
                    <path d="M5 3L3 5l2 2M11 3l2 2-2 2M6 13h4" />
                  </svg>
                }
              }
            }
          </button>
        }

        <!-- Divider -->
        <div class="rside__spacer"></div>

        <!-- Close -->
        <button type="button" class="rside__close" title="Close panel" (click)="close()">
          <svg
            width="14"
            height="14"
            fill="none"
            stroke="currentColor"
            stroke-width="1.8"
            viewBox="0 0 16 16"
          >
            <path d="M2 2l12 12M14 2L2 14" />
          </svg>
        </button>
      </nav>

      <!-- ── Widget panel ───────────────────────────────────────────────────── -->
      <div class="rside__panel">
        @if (widgets.widgets().length === 0) {
          <p class="rside__empty">
            No sidebar panels are enabled. Turn them on under Settings → Features.
          </p>
        } @else if (widgets.activeId().startsWith('plugin:')) {
          <app-plugin-host-widget [pluginId]="widgets.activeId().slice(7)" />
        } @else {
          @switch (widgets.activeId()) {
            @case ('notes') {
              <app-notes-widget />
            }
            @case ('bookmarks') {
              <app-bookmarks-widget />
            }
            @case ('ai') {
              <app-ai-widget />
            }
            @case ('console') {
              <app-console-widget />
            }
            @case ('clipboard') {
              <app-clipboard-widget />
            }
            @case ('sessions') {
              <app-sessions-widget />
            }
            @case ('api') {
              <app-api-tester-widget />
            }
            @case ('history') {
              <app-history-widget />
            }
            @case ('readlater') {
              <app-read-later-widget />
            }
            @case ('perf') {
              <app-performance-widget />
            }
            @case ('json') {
              <app-json-formatter-widget />
            }
            @default {
              <app-notes-widget />
            }
          }
        }
      </div>
    </aside>
  </div>
}

